INSERT INTO public.knowledge_entries
  (type, title, body, category, tags, source_type, source_id, source_title, status, confidence, created_by)
VALUES
  ('term', '피보험자 변경(생명보험)', '생명보험은 피보험자의 사망·생존을 보험사고로 하므로, 일반적으로 계약 도중 피보험자를 임의로 교체할 수 없는 것이 원칙이다. 피보험자가 사망하거나 위험이 현저히 변경된 경우에도 기존 계약의 피보험자를 다른 사람으로 바꾸는 것은 새로운 위험 인수에 해당하여 별도의 청약·고지·인수심사 절차를 거쳐야 한다. 이는 도덕적 위험과 역선택을 방지하기 위한 언더라이팅 원칙이다.', '인수심사', array['피보험자 변경','피보험자 교체','생명보험 인수','위험변경','언더라이팅'], 'cycle3_mined', 'cycle3_mined', '상법 제731조(타인의 생명보험)·제733조(보험수익자의 지정변경권)', 'ai_draft', 'medium', 'admin'),
  ('term', '진단계약(진단보험)과 무진단계약 구분', '진단계약은 인수심사 단계에서 피보험자가 병원·검진의를 통해 건강진단(혈액·소변·심전도 등)을 받아야 하는 계약으로, 가입금액이 큰 고액계약이나 고연령·유병 가능성이 있는 경우 적용된다. 무진단계약은 진단 없이 청약서 고지(자가고지)만으로 인수하는 계약이며 보장한도가 제한된다. 진단 여부는 자동인수한도와 연령·가입금액 구간에 따라 결정된다.', '인수심사', array['진단계약','무진단계약','건강진단','고액계약','인수심사'], 'cycle3_mined', 'cycle3_mined', '각 보험회사 언더라이팅(계약심사) 지침 — 생명보험협회 표준약관 체계', 'ai_draft', 'medium', 'admin'),
  ('term', '표준위험률(예정위험률)', '표준위험률은 보험료 산출의 기초가 되는 성별·연령별 사망률·발생률 통계로, 보험개발원이 산출·제공하는 참조위험률을 바탕으로 각 보험사가 예정위험률을 정한다. 인수심사에서 표준체는 이 표준위험률을 그대로 적용하고, 표준미달체는 위험률에 할증을 더해(특별위험률) 보험료를 산출한다. 위험률 차이가 할증·부담보 등 인수조건의 통계적 근거다.', '인수심사', array['표준위험률','예정위험률','참조위험률','특별위험률','보험료 산출'], 'cycle3_mined', 'cycle3_mined', '보험업감독규정 — 보험개발원 참조순보험요율', 'ai_draft', 'medium', 'admin'),
  ('term', '여명(餘命) 단축과 표준미달체 등급', '표준미달체 인수에서 질병·장해로 인한 기대여명 단축 정도를 평가해 정상 대비 추가 사망위험을 백분율(예: 표준체 100%, 150%, 200%)로 환산하고, 이를 기준으로 할증 등급(EM/EMR 등)을 부여한다. 여명 단축이 클수록 높은 할증률이 적용되며, 일정 한도를 초과하면 인수 거절 사유가 된다.', '인수심사', array['여명','기대여명 단축','표준미달체','할증 등급','사망위험 평가'], 'cycle3_mined', 'cycle3_mined', '각 보험회사 언더라이팅 매뉴얼 — 생명보험 표준미달체 위험평가 기준', 'ai_draft', 'medium', 'admin'),
  ('term', '부담보 vs 할증 선택 기준', '특정 신체부위·질병에 위험이 집중된 경우 해당 부위만 보장에서 제외하는 부담보가, 전신적 위험(고혈압·비만 등)이 있는 경우 보험료를 올리는 할증이 주로 적용된다. 위험이 한정적이고 예측 가능하면 부담보, 위험이 전반적이고 지속적이면 할증이 합리적이며, 두 방식을 동시에 적용(혼합 조건부 인수)하기도 한다. 가입자는 인수조건을 통보받고 청약 유지·철회를 선택할 수 있다.', '인수심사', array['부담보','할증','조건부 인수','인수조건 선택','위험평가'], 'cycle3_mined', 'cycle3_mined', '각 보험회사 언더라이팅 지침 — 생명·손해보험협회 표준화 인수기준', 'ai_draft', 'medium', 'admin'),
  ('term', '표준화 질병코드(KCD) 기반 인수', '인수심사는 피보험자의 병력을 한국표준질병사인분류(KCD) 코드로 변환해 각 코드별 인수 가이드(승인·부담보·할증·거절)를 적용한다. 동일 진단명도 KCD 코드의 세부 분류·중증도에 따라 인수결과가 달라지므로, 진단서·소견서상의 정확한 코드 확인이 적부조사와 보험금 심사에서 중요하다.', '인수심사', array['질병코드','KCD','질병분류','인수가이드','적부조사'], 'cycle3_mined', 'cycle3_mined', '통계청 한국표준질병사인분류(KCD) — 각 보험회사 질병별 인수기준표', 'ai_draft', 'medium', 'admin'),
  ('term', '자필서명(전자서명) 누락의 효과', '보험계약은 계약자와 피보험자(타인의 사망보험은 피보험자 동의 포함)의 자필서명 또는 전자서명을 요건으로 한다. 자필서명이 누락되면 3대 기본지키기 위반으로 품질보증해지(계약 취소) 대상이 되며, 특히 타인의 사망보험에서 피보험자 서면동의가 없으면 계약 자체가 무효가 된다.', '인수심사', array['자필서명','전자서명','피보험자 동의','품질보증해지','계약 무효'], 'cycle3_mined', 'cycle3_mined', '상법 제731조(타인의 생명보험)·생명보험 표준약관 3대 기본지키기', 'ai_draft', 'high', 'admin'),
  ('term', '건강고지(간편고지) 3·2·5 구조', '간편심사(유병자) 보험의 고지 항목은 통상 ''최근 3개월 이내 의사로부터 입원·수술·추가검사 소견'', ''최근 2년 이내 질병·상해로 입원·수술'', ''최근 5년 이내 암 등 중대질병 진단·입원·수술'' 등 핵심 질문으로 단순화된다. 고지 항목이 적은 만큼 보험료가 높고 보장이 제한되며, 표준고지로 가입 가능한 건강체는 굳이 간편심사를 선택할 필요가 없다.', '인수심사', array['간편고지','3개월 2년 5년','유병자보험','간편심사','고지 항목'], 'cycle3_mined', 'cycle3_mined', '각 보험회사 간편심사보험 약관 — 생명·손해보험협회 간편고지 가이드', 'ai_draft', 'medium', 'admin'),
  ('term', '부담보 부위(신체부위) 자동연계 질환', '신체부위 부담보를 설정하면 해당 부위뿐 아니라 의학적으로 그 부위에서 비롯되거나 연계되는 합병증·관련 질환까지 보장에서 제외되는 것이 일반적이다. 예컨대 위(胃) 부담보 시 위에서 기인한 출혈·천공 등이 함께 제외될 수 있으므로, 설계사는 부담보 범위가 단일 진단명에 한정되지 않을 수 있음을 안내해야 한다.', '인수심사', array['부담보 부위','신체부위 부담보','연계 질환','부담보 범위','인수조건'], 'cycle3_mined', 'cycle3_mined', '각 보험회사 부담보 특별약관 — 생명·손해보험협회 표준화 인수기준', 'ai_draft', 'medium', 'admin'),
  ('term', '인수 보류(심사 보류)와 추가서류 요청', '인수 보류는 청약 후 보험사가 즉시 승인·거절을 결정하지 않고 진단서·검사결과지·추가 건강진단 등 보완자료를 요청해 심사를 미루는 상태다. 보류 기간 중에는 계약이 성립되지 않아 보장이 개시되지 않으며, 요청 자료가 제출되지 않으면 청약이 철회·거절 처리될 수 있다. 거절체와 달리 자료 보완으로 승인 전환 여지가 있다.', '인수심사', array['인수 보류','심사 보류','추가서류','보완자료','미결 청약'], 'cycle3_mined', 'cycle3_mined', '각 보험회사 언더라이팅 절차 규정 — 생명보험 표준약관 제24조', 'ai_draft', 'medium', 'admin'),
  ('term', '청약철회와 인수거절·계약취소의 구분', '청약철회는 계약자가 보험증권 수령일부터 15일(청약일부터는 30일) 이내에 사유 없이 청약을 무를 수 있는 권리이고, 인수거절은 보험사가 심사 결과 위험을 받아들이지 않는 것이며, 계약취소(품질보증해지)는 3대 기본지키기 위반 시 계약자가 계약을 무효화하는 것이다. 세 가지는 주체·사유·기간이 모두 달라 혼동하면 안 된다.', '인수심사', array['청약철회','인수거절','계약취소','품질보증해지','권리 구분'], 'cycle3_mined', 'cycle3_mined', '금융소비자보호법 제46조(청약철회)·생명보험 표준약관 3대 기본지키기', 'ai_draft', 'high', 'admin'),
  ('term', '혈압·혈당 등 검진수치 인수기준', '건강진단계약이나 적부확인 시 혈압(수축기/이완기), 공복혈당, 당화혈색소(HbA1c), 간수치(AST/ALT), 단백뇨 등 검진수치가 일정 기준을 벗어나면 추가 정밀검사 요구, 할증, 부담보 또는 거절의 근거가 된다. 일시적 변동과 만성질환을 구분하기 위해 재검사·경과관찰을 요청하기도 한다.', '인수심사', array['검진수치','혈압','혈당','간수치','인수기준'], 'cycle3_mined', 'cycle3_mined', '각 보험회사 언더라이팅 매뉴얼 — 검사결과치 인수기준표', 'ai_draft', 'medium', 'admin'),
  ('term', '증액·특약 추가 시 추가 인수심사', '기존 계약의 보험가입금액을 증액하거나 새 특약을 중도 부가하면 증가하는 위험분에 대해 별도의 인수심사가 이루어지며, 청약 당시가 아닌 증액·부가 시점의 건강상태를 기준으로 고지의무를 다시 이행해야 한다. 증액분에는 새로운 보장개시일·면책기간이 적용되어 기존 계약과 시점이 달라질 수 있다.', '인수심사', array['증액','특약 추가','중도부가','추가 인수심사','재고지'], 'cycle3_mined', 'cycle3_mined', '각 보험회사 계약변경(증액·특약부가) 약관 — 생명보험 표준약관', 'ai_draft', 'medium', 'admin'),
  ('term', '인수조건(부담보·할증) 설명의무', '보험사가 부담보·할증 등 표준과 다른 조건으로 인수하면, 모집종사자는 청약자에게 인수조건의 내용과 그로 인한 보장 제한·추가보험료를 명확히 설명하고 동의를 받아야 한다. 인수조건을 제대로 설명하지 않은 채 계약을 성립시키면 설명의무 위반으로 분쟁·배상책임 소지가 있으며, 가입자는 조건을 거부하고 청약을 철회할 수 있다.', '인수심사', array['인수조건 설명','조건부 인수 안내','설명의무','부담보 설명','청약 동의'], 'cycle3_mined', 'cycle3_mined', '금융소비자보호법 제19조(설명의무)·보험업법 제95조의2', 'ai_draft', 'high', 'admin'),
  ('term', '손해보험 물건 종별(주택·일반·공장물건)', '화재보험 등 일반손해보험의 인수·요율은 보험목적물을 주택물건, 일반물건, 공장물건, 창고물건 등 물건 종별로 구분해 적용한다. 종별에 따라 화재 위험도와 기본요율이 달라지고, 건물 구조급수(내화·준내화·비내화)와 점유 용도에 따라 할인·할증이 가산된다. 물건 종별을 잘못 고지하면 보험금 비례삭감 사유가 된다.', '인수심사', array['물건 종별','주택물건','일반물건','공장물건','화재보험 요율'], 'cycle3_mined', 'cycle3_mined', '손해보험 화재보험 표준약관 — 보험개발원 화재보험 참조요율', 'ai_draft', 'medium', 'admin'),
  ('term', '동산·재고자산 보험가액 평가(시가·재조달가액)', '손해보험 인수에서 건물·기계·집기 등은 재조달가액(같은 것을 새로 마련하는 비용)에서 감가상각을 뺀 시가로 보험가액을 평가하는 것이 원칙이며, 재고자산은 시가(시장가격)로 평가한다. 보험가입금액이 보험가액보다 낮으면 일부보험으로 비례보상되고, 높으면 초과보험으로 무효 부분이 생기므로 적정 가액 평가가 인수의 핵심이다.', '인수심사', array['보험가액 평가','재조달가액','시가','일부보험','초과보험'], 'cycle3_mined', 'cycle3_mined', '상법 제676조(손해액의 산정기준)·손해보험 표준약관', 'ai_draft', 'medium', 'admin'),
  ('term', '보험계약 인수 정보 공유(보험신용정보)', '보험사는 보험계약 인수·보험금 지급 심사를 위해 보험계약정보·사고정보 등을 한국신용정보원의 보험신용정보통합시스템 등을 통해 조회·공유할 수 있으며, 이는 계약자의 개인(신용)정보 수집·이용 동의를 전제로 한다. 다수 보험사에서의 거절·다중계약 이력은 역선택·도덕적 위험 평가에 활용된다.', '인수심사', array['보험신용정보','인수 거절 이력','다중계약 조회','신용정보원','개인정보 동의'], 'cycle3_mined', 'cycle3_mined', '신용정보의 이용 및 보호에 관한 법률 — 한국신용정보원 보험신용정보통합조회시스템', 'ai_draft', 'medium', 'admin'),
  ('term', '고지의무자 — 계약자·피보험자 범위', '고지의무를 부담하는 자는 보험계약자와 피보험자이며, 보험수익자는 고지의무자가 아니다. 타인을 위한 보험이나 타인의 생명보험에서는 그 타인(피보험자)의 건강·직업 상태가 고지 대상이므로, 계약자가 피보험자의 정보를 정확히 확인해 고지해야 한다. 누가 고지의무자인지에 따라 고지의무위반의 귀책과 해지 효과가 달라진다.', '인수심사', array['고지의무자','계약자','피보험자','수익자','고지 대상'], 'cycle3_mined', 'cycle3_mined', '상법 제651조(고지의무)·생명보험 표준약관 제13조', 'ai_draft', 'high', 'admin'),
  ('term', '보험계약대출(약관대출)과 인수의 무관성', '보험계약대출(약관대출)은 해약환급금 범위 내에서 받는 대출로, 신용도·소득 등 별도의 인수심사 없이 가입자의 적립금을 담보로 실행된다. 보장은 그대로 유지되나 대출 원리금이 보험금·환급금에서 공제되며, 미상환 이자가 누적되면 환급금을 초과해 계약이 해지될 수 있다. 인수심사 대상인 신규계약과 구분된다.', '인수심사', array['약관대출','보험계약대출','해약환급금','인수 무관','적립금 담보'], 'cycle3_mined', 'cycle3_mined', '생명보험 표준약관 제33조(보험계약대출)', 'ai_draft', 'high', 'admin'),
  ('term', '보험계약자·피보험자 분리 설계(계약자=피보험자 불일치)', '보험계약자(보험료 납입·권리 행사 주체)와 피보험자(보험사고 대상)는 동일인이 아닐 수 있으며, 분리 설계 시 타인의 생명보험에서는 피보험자의 서면동의가 필수다. 계약자·피보험자·수익자의 조합에 따라 증여세·상속세 과세와 도덕적 위험 평가가 달라지므로, 인수심사와 세무 설계 양면에서 관계 설정을 확인해야 한다.', '인수심사', array['계약자 피보험자 분리','타인의 생명보험','서면동의','관계 설정','도덕적 위험'], 'cycle3_mined', 'cycle3_mined', '상법 제731조(타인의 생명보험)·제733조', 'ai_draft', 'high', 'admin'),
  ('term', '전자청약(모바일 청약)과 고지·서명 효력', '전자청약은 태블릿·모바일을 통해 청약서 작성·고지·전자서명·약관 교부를 전자적으로 처리하는 방식으로, 종이청약과 동일한 법적 효력을 가진다. 전자서명·본인인증이 적법하게 이루어지면 자필서명 요건을 충족한 것으로 보며, 약관·청약서 부본의 전자적 교부와 설명 절차(완전판매)가 정상 이행되어야 품질보증해지 사유가 발생하지 않는다.', '인수심사', array['전자청약','모바일 청약','전자서명','약관 전자교부','완전판매'], 'cycle3_mined', 'cycle3_mined', '전자서명법·보험업법 제96조(통신수단 모집)·생명보험 표준약관', 'ai_draft', 'medium', 'admin'),
  ('term', '대인배상 I·II (자동차보험)', '자동차보험의 대인배상은 자동차 사고로 타인을 다치게 하거나 사망케 한 경우의 손해를 보상한다. 대인배상 I은 자동차손해배상보장법상 의무가입 담보로 책임보험 한도(사망·후유장해 1명당 최대 1억5천만원, 부상은 부상등급에 따라 1급 최고 2천만원~14급 80만원) 내에서 보상하고, 대인배상 II는 책임보험 초과분을 보상하는 임의가입 담보다. 의무보험 미가입 시 자동차손해배상보장법에 따라 과태료 및 운행 제한 대상이 된다.', '보장담보', array['대인배상','자동차보험','의무보험','책임보험','대인1대인2'], 'cycle3_mined', 'cycle3_mined', '자동차손해배상 보장법 제5조·제8조, 동법 시행령 별표, 자동차보험 표준약관(금융감독원)', 'ai_draft', 'high', 'admin'),
  ('term', '대물배상 (자동차보험)', '대물배상은 자동차 사고로 타인의 재물(상대 차량·시설물 등)에 끼친 손해를 보상하는 담보다. 자동차손해배상보장법상 사고 1건당 2천만원 한도가 의무가입이며, 그 이상은 임의가입으로 가입금액을 설정한다. 실무에서는 고가 차량·시설물 손해를 대비해 의무한도를 크게 초과하는 금액(수억원)으로 가입하는 것이 일반적이다.', '보장담보', array['대물배상','자동차보험','의무보험','재물손해','가입금액'], 'cycle3_mined', 'cycle3_mined', '자동차손해배상 보장법 제5조, 동법 시행령, 자동차보험 표준약관(금융감독원)', 'ai_draft', 'high', 'admin'),
  ('term', '자기신체사고·자동차상해 (자손·자상)', '자기신체사고(자손)는 피보험자 본인 및 동승자가 자동차 사고로 사망·부상한 경우를 보상하는 담보로 사망·부상별 정액 한도로 지급한다. 자동차상해(자상)는 자손을 대체·확장한 담보로 과실 비율과 무관하게 실제 치료비·위자료 등을 보다 폭넓게 보상하여 보상 수준이 높다. 두 담보는 동시에 가입할 수 없고 택일한다.', '보장담보', array['자기신체사고','자동차상해','자손','자상','자동차보험'], 'cycle3_mined', 'cycle3_mined', '자동차보험 표준약관(금융감독원), 손해보험협회 자동차보험 안내자료', 'ai_draft', 'high', 'admin'),
  ('term', '자기차량손해 (자차)', '자기차량손해(자차)는 피보험자동차가 사고·충돌·접촉·화재·도난 등으로 입은 손해를 보상하는 담보다. 보상 시 차량가액 기준으로 자기부담금(물적사고 할증기준 연동, 통상 손해액의 20%·최소~최대 한도)이 적용된다. 단독사고·가해자 불명사고도 약관에서 정한 범위에서 보상되며, 차량 노후·시세 하락에 따라 가입금액이 조정된다.', '보장담보', array['자기차량손해','자차','자동차보험','자기부담금','차량가액'], 'cycle3_mined', 'cycle3_mined', '자동차보험 표준약관(금융감독원)', 'ai_draft', 'high', 'admin'),
  ('term', '무보험자동차에 의한 상해', '무보험자동차에 의한 상해는 피보험자가 무보험·뺑소니 차량 등에 의해 사고를 당해 다치거나 사망했을 때 보상하는 담보다. 가해 차량이 대인배상 II에 가입하지 않았거나 가해자를 알 수 없는 경우 본인 보험으로 손해를 보전받을 수 있다. 보상 후 보험회사는 가해자에게 구상권을 행사한다.', '보장담보', array['무보험차상해','뺑소니','자동차보험','구상권','피해자보호'], 'cycle3_mined', 'cycle3_mined', '자동차보험 표준약관(금융감독원)', 'ai_draft', 'high', 'admin'),
  ('term', '다른 자동차 운전담보 특약', '다른 자동차 운전담보 특약은 피보험자가 자신의 차가 아닌 타인 소유의 다른 자동차를 일시적으로 운전하다 사고가 난 경우, 본인 자동차보험의 대인·대물 등 담보를 적용해 보상받을 수 있게 하는 특약이다. 약관에서 정한 ''다른 자동차''의 범위(동일·유사 차종, 통상 사용하지 않는 차 등)와 제외 사유를 충족해야 한다.', '보장담보', array['다른자동차운전담보','자동차보험특약','임시운전','대체운전','담보적용'], 'cycle3_mined', 'cycle3_mined', '자동차보험 표준약관(금융감독원) 특별약관', 'ai_draft', 'medium', 'admin'),
  ('term', '운전자보험 형사합의지원금(교통사고처리지원금)', '운전자보험의 형사합의지원금(교통사고처리지원금)은 자동차 사고로 타인을 사망케 하거나 중상해·중대법규위반 사고를 일으켜 형사합의가 필요한 경우 합의금을 지원하는 담보다. 자동차보험의 대인배상(민사 손해배상)과 별개로 형사책임에 대응하는 비용으로, 중대법규위반(12대 중과실) 등 약관상 지급사유를 충족해야 한다.', '보장담보', array['형사합의지원금','교통사고처리지원금','운전자보험','12대중과실','형사책임'], 'cycle3_mined', 'cycle3_mined', '운전자보험 표준약관(손해보험협회), 교통사고처리 특례법', 'ai_draft', 'high', 'admin'),
  ('term', '운전자보험 벌금·변호사선임비용 담보', '운전자보험의 벌금 담보는 자동차 사고로 타인의 신체에 상해를 입혀 벌금형이 확정된 경우 벌금액을 보상하고, 변호사선임비용 담보는 구속·기소 등으로 변호사를 선임할 때의 비용을 보상한다. 벌금은 1사고당 한도(대인사고 통상 최대 2천만원, 어린이보호구역 등 가중 시 최대 3천만원) 내에서 지급되며, 음주·무면허·뺑소니 사고는 보상하지 않는다. 행정처분(범칙금·과태료)과는 구분된다.', '보장담보', array['운전자보험','벌금담보','변호사선임비용','교통사고','형사비용'], 'cycle3_mined', 'cycle3_mined', '운전자보험 표준약관(손해보험협회), 도로교통법, 특정범죄가중처벌법 제5조의13', 'ai_draft', 'high', 'admin'),
  ('term', '자기부담금 환급(자동차보험 대물·자차)', '자기부담금 환급은 자차사고에서 피보험자가 먼저 부담한 자기부담금을 사후 회수하는 절차를 말한다. 사고에 상대방 과실이 있어 보험회사가 상대 보험사로부터 구상(대위)에 성공하면, 피보험자가 부담했던 자기부담금을 과실비율에 따라 돌려받을 수 있다. 자동 환급되지 않는 경우 청구가 필요할 수 있다.', '보장담보', array['자기부담금환급','자차','구상','과실비율','자동차보험'], 'cycle3_mined', 'cycle3_mined', '자동차보험 표준약관(금융감독원), 손해보험협회 안내자료', 'ai_draft', 'medium', 'admin'),
  ('term', '재조달가액 (신가보험)', '재조달가액은 보험목적물을 사고 시점에 동일하거나 동등한 새 물건으로 다시 취득·재건축하는 데 드는 비용을 말한다. 재조달가액 기준으로 가입하면 감가상각을 공제하지 않고 신품 가격으로 보상받을 수 있어, 시가(감가 후 가액) 기준보다 보상액이 크다. 주로 건물·기계·집기 등 재물보험에서 협정한다.', '보장담보', array['재조달가액','신가보험','재물보험','감가상각','시가'], 'cycle3_mined', 'cycle3_mined', '화재보험·재물보험 표준약관(손해보험협회)', 'ai_draft', 'high', 'admin'),
  ('term', '기평가보험 (협정보험가액)', '기평가보험은 보험계약 체결 시 당사자가 보험가액을 미리 협정(약정)해 두는 보험이다. 사고 발생 시 협정가액을 보험가액으로 추정하여 손해액 산정 기준으로 삼아 가액 다툼을 줄인다. 다만 협정보험가액이 사고 시 실제 보험가액을 현저히 초과하면 그 사고 발생 시의 가액을 보험가액으로 한다(상법 제670조).', '보장담보', array['기평가보험','협정보험가액','보험가액','손해보험','상법'], 'cycle3_mined', 'cycle3_mined', '상법 제670조(기평가보험), 손해보험 표준약관', 'ai_draft', 'high', 'admin'),
  ('term', '미평가보험', '미평가보험은 보험계약 시 보험가액을 정하지 않고, 보험사고가 발생한 때와 곳의 가액을 기준으로 사후에 보험가액을 산정하는 손해보험이다. 상법은 사고 발생 시의 가액을 보험가액으로 한다고 정하며(제671조), 화재보험 등 다수 재물보험이 미평가 방식을 따른다. 기평가보험과 대비되는 개념이다.', '보장담보', array['미평가보험','보험가액','손해보험','상법','사고시가액'], 'cycle3_mined', 'cycle3_mined', '상법 제671조(미평가보험), 손해보험 표준약관', 'ai_draft', 'high', 'admin'),
  ('term', '화재보험 풍수재·붕괴·도난 특약', '주택·일반물건 화재보험은 기본담보(화재·벼락·폭발·파열)에 더해 풍수재(태풍·홍수·해일 등), 건물 붕괴·침강, 도난 등을 특약으로 보장한다. 풍수재 특약은 자연재해로 인한 건물·동산 손해를 보상하나 지진은 별도 특약이 필요한 경우가 많다. 특약별로 보상한도·자기부담금·면책 사유가 다르므로 약관 확인이 필요하다.', '보장담보', array['화재보험','풍수재특약','도난특약','붕괴','자연재해'], 'cycle3_mined', 'cycle3_mined', '화재보험 표준약관(손해보험협회)', 'ai_draft', 'medium', 'admin'),
  ('term', '일상생활배상책임 특약', '일상생활배상책임 특약은 피보험자가 일상생활 중 타인의 신체나 재물에 손해를 입혀 법률상 배상책임을 지게 된 경우(예: 자전거 사고, 누수로 아랫집 피해, 반려동물이 타인을 물어 다치게 한 경우 등)를 보상하는 특약이다. 자기부담금이 적용되며, 고의·직무 수행 중 사고·차량 운행 등은 면책된다. 가족형(가족일상생활배상책임)으로 확장 가입할 수 있다.', '보장담보', array['일상생활배상책임','가족일상생활배상','누수','반려동물','배상책임특약'], 'cycle3_mined', 'cycle3_mined', '배상책임보험 표준약관(손해보험협회)', 'ai_draft', 'high', 'admin'),
  ('term', '중복가입 비례분담 (일상생활배상책임 등 실손형 특약)', '일상생활배상책임 같은 실손보상형 배상책임 특약은 여러 보험에 중복 가입해도 실제 손해액을 초과해 보상받을 수 없고, 각 보험회사가 보상책임액 비율에 따라 비례분담한다. 따라서 동일 담보를 여러 건 가입해도 손해액 한도 내에서만 분담 지급되므로 무조건 많이 가입한다고 더 받는 것은 아니다. 정액형 담보(진단비 등)와 구분된다.', '보장담보', array['비례분담','중복가입','일상생활배상책임','실손형특약','중복보상'], 'cycle3_mined', 'cycle3_mined', '배상책임보험 표준약관(손해보험협회), 상법 제672조(중복보험)', 'ai_draft', 'high', 'admin'),
  ('term', '질병후유장해 담보', '질병후유장해 담보는 질병으로 인해 신체에 영구적 또는 약관상 정한 후유장해가 남았을 때 장해지급률에 따라 보험금을 지급하는 담보다. 상해후유장해가 사고(상해)를 원인으로 하는 것과 달리, 질병후유장해는 암·뇌혈관·근골격계 질환 등 질병을 원인으로 한다. 동일 부위 장해는 기지급분 공제 등 약관상 산정 기준이 적용된다.', '보장담보', array['질병후유장해','장해지급률','질병담보','후유장해','보장범위'], 'cycle3_mined', 'cycle3_mined', '질병·상해보험 표준약관(손해보험협회) 장해분류표', 'ai_draft', 'high', 'admin'),
  ('term', '장해분류표 (13개 신체부위)', '장해분류표는 상해·질병보험에서 후유장해를 판정하는 기준표로, 눈·귀·코·씹어먹기/말하기·외모·척추(등뼈)·체간골·팔·다리·손가락·발가락·흉복부장기/비뇨생식기·신경계/정신행동 등 신체부위별로 장해상태와 지급률을 정한다. 같은 부위 내 장해는 지급률을 합산하되 한도가 있고, 다른 부위는 각각 합산한다. 약관 개정에 따라 분류 항목·지급률 기준이 달라질 수 있다.', '보장담보', array['장해분류표','후유장해','지급률','신체부위','판정기준'], 'cycle3_mined', 'cycle3_mined', '질병·상해보험 표준약관(손해보험협회) 별표 장해분류표', 'ai_draft', 'medium', 'admin'),
  ('term', 'ADL (일상생활기본동작) 평가', 'ADL(Activities of Daily Living, 일상생활기본동작)은 이동하기·식사하기·화장실 사용·목욕하기·옷 입고 벗기 등 기본 동작 수행 능력을 평가하는 지표로, 장기간병(LTC)·간병보험에서 보험금 지급사유 판정에 사용된다. 약관에서 정한 일정 수 이상의 동작을 스스로 할 수 없는 상태(일상생활장해)가 지속되면 진단·간병 보험금이 지급된다.', '보장담보', array['ADL','일상생활기본동작','간병보험','장기간병','지급사유'], 'cycle3_mined', 'cycle3_mined', '장기간병보험 표준약관(손해보험협회·생명보험협회)', 'ai_draft', 'high', 'admin'),
  ('term', '수술비 분류(수술분류표 종별 차등)', '수술비 담보는 약관의 수술분류표에 따라 수술의 종류·난이도를 1~5종(상품에 따라 1~7종 등) 등으로 구분하고, 종별로 차등 지급한다. 같은 질병이라도 시술 방식이 약관상 ''수술''의 정의(절단·절제 등 관혈적 조작)에 해당하는지에 따라 지급 여부가 달라진다. 단순 처치·검사 목적 시술은 수술로 인정되지 않을 수 있다.', '보장담보', array['수술비','수술분류표','수술종별','관혈적','지급기준'], 'cycle3_mined', 'cycle3_mined', '질병·상해보험 표준약관(손해보험협회) 수술분류표', 'ai_draft', 'medium', 'admin'),
  ('term', '표적항암약물허가치료비 담보', '표적항암약물허가치료비 담보는 암 치료 과정에서 식약처 허가를 받은 표적항암제를 사용한 약물치료를 받았을 때 보장하는 담보다. 일반 항암치료비와 달리 고가의 표적·면역항암제 사용을 대비하는 담보로, 약관에서 정한 허가 항암제 투여·치료 회차 기준 등을 충족해야 지급된다. 비급여 항암치료 부담이 커지면서 가입 관심이 높은 항목이다.', '보장담보', array['표적항암약물치료비','항암치료','암보험','비급여항암','고가치료'], 'cycle3_mined', 'cycle3_mined', '암보험 표준약관(손해보험협회·생명보험협회), 식약처 의약품 허가사항', 'ai_draft', 'medium', 'admin'),
  ('term', '암 보장개시일 90일 면책(대기기간)', '암 진단비 담보는 보험계약일부터 그날을 포함하여 90일이 지난 다음 날부터 보장이 개시되며, 그 90일의 면책기간 중 암으로 진단확정되면 해당 암 담보 계약은 무효가 되고 보험금이 지급되지 않는다. 어린이·청소년·유사암 등 일부 담보는 면책기간이 적용되지 않을 수 있다. 갱신·부활 시에도 면책 적용 여부를 약관에서 확인해야 한다.', '보장담보', array['암보장개시일','90일면책','대기기간','암진단비','면책'], 'cycle3_mined', 'cycle3_mined', '암보험 표준약관(손해보험협회·생명보험협회)', 'ai_draft', 'high', 'admin'),
  ('term', '유사암 진단비 (소액암)', '유사암(소액암)은 일반암과 구분되는 갑상선암, 기타피부암, 경계성종양, 제자리암(상피내암), 비침습 방광암 등을 묶어 부르는 실무 용어로, 진단비가 일반암 가입금액의 일부(통상 10~30%)로 책정된다. 약관마다 유사암의 범위와 지급비율, 횟수 한도가 다르므로 보장범위 확인이 중요하다.', '보장담보', array['유사암','소액암','갑상선암','경계성종양','진단비'], 'cycle3_mined', 'cycle3_mined', '암보험 표준약관(손해보험협회·생명보험협회), 한국표준질병사인분류(KCD)', 'ai_draft', 'high', 'admin'),
  ('term', '질병코드(KCD) 기준 담보 판정', '진단비·수술비 등 질병 담보는 한국표준질병·사인분류(KCD)의 질병분류코드를 기준으로 지급 여부를 판정한다. 약관은 보장 대상 질병을 KCD 코드 범위(예: 뇌혈관질환 I60~I69, 허혈성심장질환 I20~I25 등)로 특정하며, 진단서상 코드가 약관 범위에 해당해야 보험금이 지급된다. KCD 개정 시에는 계약 당시 적용 분류를 따르는 것이 원칙이다.', '보장담보', array['KCD','질병코드','질병분류','진단비','지급판정'], 'cycle3_mined', 'cycle3_mined', '통계청 한국표준질병·사인분류(KCD), 질병보험 표준약관', 'ai_draft', 'high', 'admin'),
  ('term', '허혈성심장질환 진단비', '허혈성심장질환 진단비는 심장에 혈액 공급이 부족해 발생하는 질환군(KCD I20~I25, 협심증·급성심근경색 등 포함)으로 진단확정 시 보장하는 담보다. 급성심근경색만 보장하는 담보보다 보장 범위가 넓어 협심증 등도 포함된다. 약관별로 보장 코드 범위와 진단확정 기준(검사·소견 요건)이 다르므로 확인이 필요하다.', '보장담보', array['허혈성심장질환','협심증','심근경색','진단비','I20I25'], 'cycle3_mined', 'cycle3_mined', '질병보험 표준약관(손해보험협회), 한국표준질병사인분류(KCD)', 'ai_draft', 'high', 'admin'),
  ('term', '보철·치아보존 치료비 (치아보험 담보)', '치아보험은 충치·치주질환 등으로 인한 보존치료(아말감·레진·인레이 등)와 보철치료(크라운·브리지·임플란트·틀니 등)를 담보별로 보장한다. 치료 종류별 정액 또는 비례 보상이며, 가입 후 면책기간·감액기간(통상 90일 면책, 1~2년 감액)과 연간 치료 횟수 한도가 적용된다. 가입 전 기존 치아 상태에 따른 부담보가 설정될 수 있다.', '보장담보', array['치아보험','보철치료','임플란트','치아보존','면책감액'], 'cycle3_mined', 'cycle3_mined', '치아보험 표준약관(손해보험협회)', 'ai_draft', 'medium', 'admin'),
  ('term', '골절·깁스 진단비 담보', '골절 진단비는 상해사고로 약관상 정한 골절(한국표준질병사인분류상 골절 코드)을 진단받으면 정액으로 지급하는 담보이며, 깁스(부목 고정) 치료비는 골절·탈구 등으로 깁스 치료를 받은 경우 별도로 보장한다. 치아 파절·압박골절 등 약관상 보장 범위와 제외 사유, 동일사고 1회 지급 여부를 확인해야 한다.', '보장담보', array['골절진단비','깁스치료비','상해담보','부목','정액보장'], 'cycle3_mined', 'cycle3_mined', '상해보험 표준약관(손해보험협회), 한국표준질병사인분류(KCD)', 'ai_draft', 'medium', 'admin'),
  ('term', '화상 진단·수술비 담보', '화상 담보는 상해사고로 인한 화상(심재성 2도 이상 등 약관상 정한 정도·범위)을 진단받거나 화상으로 수술·피부이식을 받은 경우 보장한다. 화상의 깊이(표재성·심재성)와 체표면적 비율에 따라 지급 여부·금액이 결정되며, 약관에서 정한 화상분류 기준을 충족해야 한다. 직업·취미상 화상 위험이 높은 경우 인수 시 고려된다.', '보장담보', array['화상진단비','화상수술비','심재성화상','피부이식','상해담보'], 'cycle3_mined', 'cycle3_mined', '상해보험 표준약관(손해보험협회)', 'ai_draft', 'medium', 'admin'),
  ('term', '응급실 내원비 (응급/비응급 차등)', '응급실 내원비(응급실 진료비) 담보는 질병·상해로 응급실을 이용한 경우 보장하는 담보다. 다수 약관이 응급환자(응급의료에 관한 법률상 응급증상)와 비응급환자를 구분해 지급금액을 차등하거나, 비응급 내원은 보장 제외·감액한다. 응급/비응급 판정은 응급의료에 관한 법률 시행규칙상 응급증상 기준을 따른다.', '보장담보', array['응급실내원비','응급실진료비','응급증상','비응급','차등보장'], 'cycle3_mined', 'cycle3_mined', '질병·상해보험 표준약관, 응급의료에 관한 법률 시행규칙(응급증상 및 이에 준하는 증상)', 'ai_draft', 'medium', 'admin'),
  ('term', '중환자실(ICU) 입원일당', '중환자실 입원일당은 질병·상해로 중환자실(집중치료실, ICU)에 입원한 경우 일반병실 입원일당과 별도로 가산해 지급하는 담보다. 중환자실 입원 1일당 정액으로 지급되며, 약관에서 정한 중환자실의 정의·1회 입원당 지급일수 한도가 적용된다. 일반 입원일당과 중복해 받을 수 있는지는 약관 확인이 필요하다.', '보장담보', array['중환자실입원일당','ICU','입원일당','집중치료','정액보장'], 'cycle3_mined', 'cycle3_mined', '질병·상해보험 표준약관(손해보험협회·생명보험협회)', 'ai_draft', 'medium', 'admin'),
  ('term', '동일질병·동일사고 입원일수 통산(180일 한도)', '입원일당·입원비 담보는 동일한 질병 또는 동일 사고로 인한 입원을 1회 입원으로 보아 약관상 1회 입원당 지급일수 한도(통상 180일)를 적용한다. 퇴원 후 일정 기간(예: 180일) 내 같은 원인으로 재입원하면 계속 입원으로 통산하며, 그 기간이 지난 뒤의 재입원은 새로운 입원으로 본다. 한도를 초과하는 입원일수는 보장되지 않는다.', '보장담보', array['입원일수통산','180일한도','동일질병','재입원','입원일당'], 'cycle3_mined', 'cycle3_mined', '질병·상해보험·실손의료보험 표준약관(금융감독원·손해보험협회) 입원의 정의·지급한도', 'ai_draft', 'high', 'admin'),
  ('term', '천재지변·전쟁·핵연료 면책(공통 면책)', '대부분의 보험약관은 전쟁·혁명·내란·사변·폭동 등 비상위험과 핵연료물질·방사선에 의한 사고를 보상하지 않는 공통 면책사유로 정한다. 천재지변(지진·분화·해일 등)도 담보·약관에 따라 면책되거나 별도 특약으로만 보장된다. 이는 위험의 거대성·예측 곤란성 때문에 일반 담보에서 제외하는 것이다.', '보장담보', array['공통면책','전쟁면책','핵연료','천재지변','비상위험'], 'cycle3_mined', 'cycle3_mined', '손해보험·생명보험 표준약관(손해보험협회·생명보험협회) 보상하지 않는 손해', 'ai_draft', 'high', 'admin'),
  ('term', '음주·무면허운전 면책 및 사고부담금', '자동차보험·운전자보험 등에서 음주운전·무면허운전·뺑소니로 인한 사고는 보험금이 면책되거나, 자동차보험 의무담보(대인·대물)는 보상하되 운전자가 사고부담금을 부담하도록 한다. 2022년 7월 자동차손해배상보장법 개정으로 음주·무면허·뺑소니 사고부담금이 의무보험 한도 전액(대인 1명당 사망 1.5억·부상 3천만원, 대물 1건당 2천만원)까지 상향되었으며, 자기차량손해 등 임의담보는 면책되는 경우가 많다. 도덕적 위험 방지를 위한 제도다.', '보장담보', array['음주운전면책','무면허','사고부담금','자동차보험','뺑소니'], 'cycle3_mined', 'cycle3_mined', '자동차손해배상 보장법(2022.7 개정), 자동차보험 표준약관(금융감독원)', 'ai_draft', 'high', 'admin'),
  ('term', '자살 면책 2년 경과 후 보장(재해 외 사망)', '생명보험 약관은 피보험자의 고의 자해·자살을 원칙적으로 면책하되, 계약의 보장개시일(또는 부활일)부터 2년이 지난 후 자살한 경우에는 재해 외의 원인에 해당하는 사망보험금(일반사망보험금)을 지급한다. 다만 재해사망보험금은 자살에 지급되지 않으며, 심신상실 등 자유로운 의사결정을 할 수 없는 상태에서의 자살은 별도 판단된다.', '보장담보', array['자살면책','2년경과','생명보험','재해사망','책임개시일'], 'cycle3_mined', 'cycle3_mined', '생명보험 표준약관(생명보험협회) 보험금을 지급하지 않는 사유', 'ai_draft', 'high', 'admin'),
  ('term', '보장 중복 점검(정액형·실손형 구분)', '가입자가 여러 보험에 동일·유사 담보(예: 입원일당, 진단비, 후유장해)를 중복 가입한 경우, 정액형 담보는 각 계약에서 약정한 금액을 모두 받을 수 있으나 실손형 담보는 비례보상되어 손해액을 초과해 받을 수 없다. 따라서 보장 설계 시 정액·실손 구분과 담보 중복 여부를 점검해 과다·중복 가입을 줄이는 것이 실무 원칙이다.', '보장담보', array['보장중복','정액형','실손형','보장설계','중복점검'], 'cycle3_mined', 'cycle3_mined', '손해보험·생명보험 표준약관, 금융소비자보호법 적합성 원칙', 'ai_draft', 'medium', 'admin'),
  ('term', '단체보험(단체상해·단체실손) 담보 구조', '단체보험은 사업주·단체가 소속 임직원 등 5인 이상을 일괄 피보험자로 가입하는 보험으로, 단체상해·단체실손·단체정기 등이 있다. 개인보험과 달리 규약·명부에 따라 피보험자가 관리되며, 타인의 사망을 보험금 지급사유로 하는 경우 단체규약이 있으면 피보험자 서면동의를 갈음할 수 있다. 퇴직 시 개인계약 전환 가능 여부는 약관에 따른다.', '보장담보', array['단체보험','단체상해','단체실손','서면동의','피보험자관리'], 'cycle3_mined', 'cycle3_mined', '상법 제735조의3(단체보험), 단체보험 표준약관', 'ai_draft', 'high', 'admin'),
  ('term', '제3보험(질병·상해·간병) 영역 구분', '제3보험은 생명보험(사람의 생존·사망)과 손해보험(재산손해)의 성격을 동시에 갖는 보험으로, 상해·질병·간병보험이 이에 속한다. 보험업법 제4조상 제3보험상품은 사람의 질병·상해 또는 이에 따른 간병에 관해 급여를 지급하는 계약으로, 생명보험회사와 손해보험회사 모두 겸영할 수 있다. 실손의료비·진단비·간병 등 사람 신체 관련 담보가 제3보험에 해당하며, 정액보상과 실손보상이 혼재한다.', '보장담보', array['제3보험','상해보험','질병보험','간병보험','겸영'], 'cycle3_mined', 'cycle3_mined', '보험업법 제2조·제4조(보험상품의 종류·보험업의 허가)', 'ai_draft', 'high', 'admin'),
  ('term', '청약철회 청약일과 보험증권 수령일 기준(15일·30일)', '보험계약자(일반금융소비자)는 보험증권을 받은 날부터 15일 이내(청약을 한 날부터 30일 이내)에 청약을 철회할 수 있다. 두 기간 중 먼저 끝나는 기준이 적용되어, 청약일로부터 30일이 지나면 증권을 받은 날부터 15일이 남아 있어도 철회가 불가능하다. 진단계약(건강상태 진단 지원 계약), 보장기간 90일 이내 계약, 전문금융소비자 계약 등은 철회 대상에서 제외된다.', '계약청약고지', array['청약철회 기간','15일','30일','증권 수령일','청약일 기준'], 'cycle3_mined', 'cycle3_mined', '금융소비자보호법 제46조, 보험업감독규정', 'ai_draft', 'high', 'admin'),
  ('term', '건강진단 계약의 청약철회 가능 여부', '피보험자가 건강진단을 받아야 하는 진단계약은 일반 무진단계약과 달리 청약철회 대상에서 제외된다. 회사가 건강상태 진단을 지원하는 보험계약은 위험인수 절차가 진행되므로 금융소비자보호법령상 철회권 행사가 제한되며, 구체적 범위는 약관과 시행령으로 확인해야 한다.', '계약청약고지', array['진단계약','청약철회 제외','건강진단','무진단계약','철회 제한'], 'cycle3_mined', 'cycle3_mined', '금융소비자보호법 시행령 제37조, 생명보험 표준약관', 'ai_draft', 'high', 'admin'),
  ('term', '전화·우편·인터넷 모집계약의 철회 특례', '통신판매(TM·CM)로 체결한 보험계약은 모집과정 녹취·전자서명 등의 절차가 적용되며, 청약철회 의사표시도 서면 외에 전화·전자우편 등 통신수단으로 할 수 있다. 통신수단 모집 시 보험회사는 철회권 등 소비자 권리를 명확히 안내할 의무가 있다.', '계약청약고지', array['통신판매 철회','TM CM','전자서명','녹취','철회 의사표시'], 'cycle3_mined', 'cycle3_mined', '보험업법 제96조, 금융소비자보호법 제46조', 'ai_draft', 'medium', 'admin'),
  ('term', '고지의무 이행의 상대방(보험설계사의 고지수령권 부존재)', '고지의무는 보험자 또는 고지수령권을 가진 자에게 이행해야 효력이 있다. 판례·실무상 보험설계사(모집인)는 원칙적으로 고지수령권이 없어, 계약자가 설계사에게 구두로만 병력을 알린 경우 회사에 고지한 것으로 인정되지 않을 수 있다. 청약서 질문표에 직접 기재하는 것이 안전하다.', '계약청약고지', array['고지수령권','설계사 고지','구두 고지','질문표','고지 효력'], 'cycle3_mined', 'cycle3_mined', '상법 제651조, 대법원 판례(고지수령권)', 'ai_draft', 'high', 'admin'),
  ('term', '고지의무의 수동적 의무성(질문표 응답 의무)', '현행 상법상 고지의무는 보험자가 서면(청약서 질문표)으로 질문한 사항에 한해 사실대로 답할 의무로 운용된다(질문응답주의). 보험자가 서면으로 질문한 사항은 중요한 사항으로 추정되며, 질문하지 않은 사항을 스스로 모두 신고할 의무는 원칙적으로 없으나 질문표 범위에서 중요한 사항을 누락하면 고지의무 위반이 된다.', '계약청약고지', array['질문응답주의','수동적 고지','질문표','중요한 사항','고지 범위'], 'cycle3_mined', 'cycle3_mined', '상법 제651조의2', 'ai_draft', 'high', 'admin'),
  ('term', '고지의무 위반의 주관적 요건(고의 또는 중대한 과실)', '고지의무 위반으로 계약을 해지하려면 계약자·피보험자에게 고의 또는 중대한 과실이 있어야 한다. 단순 경과실로 알리지 못한 경우에는 해지권이 발생하지 않는다. 고의·중과실의 존재는 해지를 주장하는 보험자가 입증해야 하며, 입증하지 못하면 해지할 수 없다.', '계약청약고지', array['고의 중과실','고지위반 요건','경과실','입증책임','해지권'], 'cycle3_mined', 'cycle3_mined', '상법 제651조', 'ai_draft', 'high', 'admin'),
  ('term', '보험자의 고지의무 위반 해지권 행사 제한(보험자 악의·해태)', '보험자가 계약 당시 고지의무 위반 사실을 알았거나 과실로 알지 못한 경우에는 고지의무 위반을 이유로 계약을 해지할 수 없다(제651조 단서). 또 보험자가 위반 사실을 안 날부터 1개월 또는 계약 체결일부터 3년의 제척기간이 지나면 해지권 자체가 소멸한다.', '계약청약고지', array['보험자 악의','해지권 제한','고지위반 해지 불가','보험자 과실','해지 해태'], 'cycle3_mined', 'cycle3_mined', '상법 제651조 단서', 'ai_draft', 'high', 'admin'),
  ('term', '직업·직무 변경 통지와 보험료 정산(비례 증감)', '상해보험 등에서 직업이나 직무가 변경되어 위험등급이 달라지면 계약 후 알릴 의무에 따라 보험회사에 알려야 한다. 위험이 증가하면 변경 후 위험에 해당하는 보험료로 증액 정산되고, 위험이 감소하면 보험료가 감액될 수 있다. 통지하지 않은 채 사고가 나면 보험금이 직전 요율 대비 비례로 삭감될 수 있다.', '계약청약고지', array['직업변경 통지','위험등급','보험료 정산','상해보험','비례삭감'], 'cycle3_mined', 'cycle3_mined', '질병·상해보험 표준약관, 상법 제652조', 'ai_draft', 'high', 'admin'),
  ('term', '계약 해지 시 해약환급금 반환과 책임준비금', '보험계약이 해지되면 보험회사는 약관에 따라 산출한 해약환급금을 계약자에게 지급한다. 고지의무 위반 등으로 해지되는 경우에도 해약환급금은 지급되는 것이 원칙이나, 보험사고가 이미 발생해 보험금 지급책임이 면제되는 등의 사정에 따라 지급 범위가 달라질 수 있다.', '계약청약고지', array['계약해지 환급금','해약환급금','책임준비금','고지위반 해지 환급','환급 원칙'], 'cycle3_mined', 'cycle3_mined', '보험업감독규정, 생명보험 표준약관', 'ai_draft', 'medium', 'admin'),
  ('term', '보험사고 발생 후 계약 해지의 효력', '보험사고가 발생한 후 고지의무 위반 등을 이유로 계약을 해지하는 경우, 보험자는 원칙적으로 보험금 지급책임을 지지 않으며 이미 지급한 보험금의 반환을 청구할 수 있다. 다만 고지하지 않은 사실과 보험사고 사이에 인과관계가 없음이 증명되면 보험금을 지급해야 한다.', '계약청약고지', array['사고 후 해지','보험금 반환','인과관계','고지위반 효과','지급책임'], 'cycle3_mined', 'cycle3_mined', '상법 제655조', 'ai_draft', 'high', 'admin'),
  ('term', '부활계약의 고지의무 재이행', '실효된 계약을 부활(효력회복)할 때에는 신규 청약에 준하여 다시 고지의무를 이행해야 한다. 부활 청약 시점 기준으로 새로 발생한 병력 등 중요사항을 고지하지 않으면, 부활계약에 대해 고지의무 위반에 따른 해지가 가능하다.', '계약청약고지', array['부활 고지의무','효력회복 고지','부활 청약','재고지','부활 해지'], 'cycle3_mined', 'cycle3_mined', '상법 제650조의2, 생명보험 표준약관', 'ai_draft', 'high', 'admin'),
  ('term', '부활계약의 책임개시와 면책기간 재기산', '부활계약이 성립하면 부활 시점부터 보장이 다시 시작되며, 일부 담보는 최초 계약과 별도로 면책기간·감액기간이 다시 적용될 수 있다. 부활 전 실효기간 중 발생한 보험사고는 보장되지 않는 것이 원칙이다.', '계약청약고지', array['부활 책임개시','면책기간 재기산','실효기간 사고','감액기간','부활 보장'], 'cycle3_mined', 'cycle3_mined', '생명보험 표준약관, 상법 제650조의2', 'ai_draft', 'medium', 'admin'),
  ('term', '제1회 보험료와 승낙 전 보험사고 담보', '청약과 함께 제1회 보험료(초회보험료)를 받은 경우, 보험회사가 청약을 승낙하기 전에 보험사고가 발생하더라도 청약을 거절할 사유가 없는 한 보험금을 지급한다(승낙 전 보호). 다만 인보험에서 피보험자가 신체검사를 받아야 하는 진단계약은 검사를 받지 않은 때에는 이 보호가 적용되지 않는다.', '계약청약고지', array['초회보험료','승낙 전 사고','승낙전 담보','청약 거절사유','책임개시'], 'cycle3_mined', 'cycle3_mined', '상법 제638조의2, 생명보험 표준약관', 'ai_draft', 'high', 'admin'),
  ('term', '청약 승낙 의제(낙부통지의무 위반의 효과)', '보험자가 청약과 함께 보험료 상당액을 받은 후 다른 약정이 없으면 30일 이내에 승낙 또는 거절 통지를 발송해야 하며, 이를 게을리하면 승낙한 것으로 본다(승낙 의제). 인보험에서 피보험자가 신체검사를 받아야 하는 경우 이 기간은 신체검사를 받은 날부터 기산한다.', '계약청약고지', array['승낙 의제','낙부통지','30일 통지','청약 승낙','승낙간주'], 'cycle3_mined', 'cycle3_mined', '상법 제638조의2', 'ai_draft', 'high', 'admin'),
  ('term', '위험변경·증가 통지의무 위반 시 해지권 제척기간(1개월)', '보험기간 중 위험이 현저하게 변경·증가된 사실을 통지하지 않은 경우, 보험자는 그 사실을 안 날부터 1개월 이내에 한해 계약을 해지할 수 있다(상법 제652조 제1항). 이 기간이 지나면 통지의무 위반을 이유로 해지할 수 없으며, 고지의무 위반 해지권의 제척기간과는 별개의 규정이다.', '계약청약고지', array['통지의무 위반 해지','제척기간','1개월','위험변경 해지','해지권 소멸'], 'cycle3_mined', 'cycle3_mined', '상법 제652조', 'ai_draft', 'high', 'admin'),
  ('term', '보험계약자·피보험자의 통지의무 주체', '위험변경·증가 통지의무는 보험계약자뿐 아니라 피보험자도 부담한다. 위험의 현저한 변경·증가 사실을 안 자가 지체 없이 통지해야 하며, 누가 통지하든 회사가 안 것으로 처리된다. 통지 주체와 시점은 보험금 분쟁에서 중요한 쟁점이 된다.', '계약청약고지', array['통지의무 주체','피보험자 통지','계약자 통지','통지 시점','통지 책임'], 'cycle3_mined', 'cycle3_mined', '상법 제652조', 'ai_draft', 'medium', 'admin'),
  ('term', '보험사고 발생 통지의무와 지연 통지의 효과', '보험계약자·피보험자·수익자는 보험사고 발생을 안 때에는 지체 없이 보험자에게 통지해야 한다(상법 제657조). 통지를 게을리하여 손해가 증가한 경우 그 증가분에 대해 보험자가 책임을 지지 않을 수 있다. 다만 통지 지연만으로 보험금 전액이 면책되는 것은 아니다.', '계약청약고지', array['사고발생 통지','지연통지','손해 증가','통지 해태','면책'], 'cycle3_mined', 'cycle3_mined', '상법 제657조', 'ai_draft', 'high', 'admin'),
  ('term', '위험 증가 시 보험료 증액 청구권(해지 대안)', '보험기간 중 위험이 현저히 증가했다는 통지를 받은 경우 보험자는 계약을 해지하는 대신 1개월 내에 증가한 위험에 상응하는 보험료 증액을 청구할 수 있다. 계약자가 증액을 거절하면 보험자가 계약을 해지할 수 있다. 반대로 특별한 위험 소멸 등으로 위험이 감소하면 계약자가 보험료 감액을 청구할 수 있다.', '계약청약고지', array['보험료 증액 청구','위험 증가','보험료 감액','해지 대안','요율 조정'], 'cycle3_mined', 'cycle3_mined', '상법 제647조, 제652조', 'ai_draft', 'high', 'admin'),
  ('term', '보험수익자 변경 통지의 대항요건', '생명보험에서 보험수익자를 지정·변경한 경우, 그 사실을 보험자에게 통지하지 않으면 보험자에게 대항할 수 없다(상법 제734조). 즉 통지 전에 보험자가 종전 수익자에게 보험금을 지급하면 보험자는 면책될 수 있어, 수익자 변경 시 회사 통지가 중요하다.', '계약청약고지', array['수익자 변경 통지','대항요건','수익자 지정','보험자 면책','통지 효력'], 'cycle3_mined', 'cycle3_mined', '상법 제734조', 'ai_draft', 'medium', 'admin'),
  ('term', '고지의무 위반과 청약철회·취소권의 경합', '같은 계약에 대해 고지의무 위반에 따른 해지권, 약관 교부·설명의무 위반에 따른 취소권, 청약철회권이 동시에 문제될 수 있다. 각 권리는 행사 요건·기간·효과가 달라 소비자는 가장 유리한 권리를 선택할 수 있고, 보험회사는 해지·취소 사유를 명확히 구분해 안내해야 한다.', '계약청약고지', array['권리 경합','해지권 취소권','청약철회 비교','소비자 선택','구제수단'], 'cycle3_mined', 'cycle3_mined', '상법 제638조의3·제651조, 금융소비자보호법 제46조', 'ai_draft', 'medium', 'admin'),
  ('term', '계약 전 알릴 의무 질문표의 과거 기간 기준(최근 3개월·1년·5년)', '청약서 계약 전 알릴 의무 질문표는 통상 최근 3개월 이내 진단·투약, 최근 1년 이내 추가검사·재검사, 최근 5년 이내 입원·수술·계속 7일 이상 치료·계속 30일 이상 투약 등 기간별로 고지 대상을 정한다. 기간 구분을 잘못 이해하면 불고지 분쟁이 발생한다.', '계약청약고지', array['질문표 기간','3개월 1년 5년','과거 병력','계약 전 알릴 의무','고지 대상 기간'], 'cycle3_mined', 'cycle3_mined', '생명보험·질병상해보험 표준약관(계약 전 알릴 의무 질문표)', 'ai_draft', 'high', 'admin'),
  ('term', '계약 후 알릴 의무(직업·운전·이륜차 등 변경 통지)', '청약 후에도 직업·직무 변경, 이륜차(오토바이) 계속 운전, 위험한 취미 시작 등 약관이 정한 사항이 변경되면 계약 후 알릴 의무에 따라 회사에 통지해야 한다. 특히 이륜차 운전은 위험이 크게 증가하므로 미통지 시 사고 보험금이 삭감되거나 부지급될 수 있다.', '계약청약고지', array['계약 후 알릴 의무','이륜차 운전','직업 변경 통지','취미 변경','미통지 삭감'], 'cycle3_mined', 'cycle3_mined', '질병·상해보험 표준약관(계약 후 알릴 의무)', 'ai_draft', 'high', 'admin'),
  ('term', '보험계약 부활 시 연체보험료와 이자 납입', '계약을 부활하려면 해지·실효 시점까지의 연체된 보험료에 약관에서 정한 약정이자를 더해 납입해야 한다. 부활 청약과 회사의 승낙, 연체보험료 납입이 모두 충족되어야 효력이 회복된다.', '계약청약고지', array['부활 연체보험료','연체이자','효력회복 요건','부활 납입','부활 승낙'], 'cycle3_mined', 'cycle3_mined', '상법 제650조의2, 생명보험 표준약관', 'ai_draft', 'high', 'admin'),
  ('term', '보험료 납입연체 시 해지예고(납입최고)와 실효 절차', '계약자가 제2회 이후 계속보험료를 연체하면 보험회사는 14일(보험기간 1년 미만은 7일) 이상의 납입최고기간을 정해 서면·전화·전자문서로 연체 사실과 해지 예정을 안내해야 한다. 이 최고 절차 없이 한 계약 해지는 효력이 없다.', '계약청약고지', array['납입연체 해지','최고기간','해지예고','실효 절차','최고 미이행 해지무효'], 'cycle3_mined', 'cycle3_mined', '상법 제650조, 생명보험 표준약관', 'ai_draft', 'high', 'admin'),
  ('term', '15세 미만자 등의 사망보험 가입 제한', '15세 미만자, 심신상실자, 심신박약자의 사망을 보험사고로 하는 보험계약은 원칙적으로 무효다. 다만 심신박약자가 보험계약을 체결하거나 단체보험의 피보험자가 될 때 의사능력이 있는 경우는 예외다. 어린이보험 설계 시 사망담보 가입 가능 연령을 반드시 확인해야 한다.', '계약청약고지', array['15세 미만 사망보험','가입 제한','계약 무효','어린이보험 사망담보','심신상실자'], 'cycle3_mined', 'cycle3_mined', '상법 제732조', 'ai_draft', 'high', 'admin'),
  ('term', '보험계약의 사기에 의한 초과·중복보험', '사기로 인하여 체결된 초과보험·중복보험 계약은 무효이며, 보험자는 그 사실을 안 때까지의 보험료를 청구할 수 있다(상법 제669조 제4항, 제672조 제3항). 보험가액을 고의로 부풀려 다수 계약을 체결하는 경우가 대표적이다.', '계약청약고지', array['사기 초과보험','사기 중복보험','계약 무효','보험료 청구','보험가액 부풀리기'], 'cycle3_mined', 'cycle3_mined', '상법 제669조, 제672조', 'ai_draft', 'high', 'admin'),
  ('term', '고지의무 위반 해지권의 제척기간(3년·1개월)', '보험자는 고지의무 위반 사실을 안 날부터 1개월 이내, 그리고 계약 체결일부터 3년 이내에 한해 해지할 수 있다(상법 제651조). 3년이 지나면 위반이 있어도 해지하지 못한다. 표준약관은 보장개시일부터 2년 등 더 짧은 기간을 정해 소비자에게 유리하게 운용한다.', '계약청약고지', array['고지위반 제척기간','3년','1개월','2년 약관','해지권 소멸'], 'cycle3_mined', 'cycle3_mined', '상법 제651조, 생명보험 표준약관(2년 조항)', 'ai_draft', 'high', 'admin'),
  ('term', '청약서 부본·약관 미교부 시 취소권(3개월)', '보험자가 청약 시 약관과 청약서 부본을 전달하지 않거나 약관의 중요 내용을 설명하지 않은 경우, 계약자는 계약이 성립한 날부터 3개월 이내에 계약을 취소할 수 있다(상법 제638조의3). 금소법상 설명의무 위반과 함께 적용되어 소비자 구제 폭이 넓다.', '계약청약고지', array['약관 미교부 취소','청약서 부본','3개월 취소권','설명의무 위반','계약 취소'], 'cycle3_mined', 'cycle3_mined', '상법 제638조의3', 'ai_draft', 'high', 'admin'),
  ('term', '보험계약의 무효·취소·해지·실효의 구별', '무효는 처음부터 효력이 없는 것, 취소는 일정 사유로 소급해 효력을 잃게 하는 것, 해지는 장래를 향해 효력을 종료시키는 것, 실효는 보험료 미납 등으로 계약 효력이 정지·상실되는 것을 말한다. 보험금 지급 여부와 보험료·환급금 정산이 각각 달라 정확한 구분이 필요하다.', '계약청약고지', array['무효 취소 해지 실효','효력 구분','소급효','장래효','보험금 정산'], 'cycle3_mined', 'cycle3_mined', '상법 보험편(제638조의3·제649조·제650조 등)', 'ai_draft', 'high', 'admin'),
  ('term', '인보험에서 보험자대위 금지 원칙', '생명보험·상해보험 등 인보험에서는 원칙적으로 보험자대위가 금지되어, 보험금을 지급한 보험자가 가해자에 대한 피보험자의 손해배상청구권을 대위 행사할 수 없다(상법 제729조). 다만 상해보험에서 당사자 간 약정이 있으면 피보험자의 권리를 해하지 않는 범위에서 제한적으로 대위가 가능하다.', '계약청약고지', array['인보험 대위금지','보험자대위','상해보험 대위 특약','손해배상청구권','청구권 대위'], 'cycle3_mined', 'cycle3_mined', '상법 제729조', 'ai_draft', 'high', 'admin'),
  ('term', '청약철회와 보험금 지급사유 발생 시 처리', '일반금융소비자가 보험금의 지급사유가 발생했음을 알면서 청약을 철회한 경우에는 청약철회의 효력이 제한되지 않는다. 즉 보장이 개시되어 보험금 지급사유가 생긴 것을 알고도 철회하여 보험료를 돌려받으면서 보험금까지 받는 것은 허용되지 않는다.', '계약청약고지', array['청약철회 사고','철회 제한','책임개시 후 사고','철회 효력','보험금 청약철회'], 'cycle3_mined', 'cycle3_mined', '금융소비자보호법 제46조, 보험 표준약관', 'ai_draft', 'medium', 'admin'),
  ('term', '보험계약 청약의 법적 성질과 승낙의 자유', '보험계약 청약은 계약자의 청약과 보험자의 승낙으로 성립하는 낙성·불요식 계약이다. 보험자는 인수심사 결과에 따라 청약을 거절할 수 있으며, 청약했다고 해서 반드시 계약이 성립하는 것은 아니다. 다만 보험료를 받고 30일 내 낙부통지를 하지 않으면 승낙이 의제된다.', '계약청약고지', array['청약 법적성질','낙성계약','승낙 자유','청약 거절','계약 성립'], 'cycle3_mined', 'cycle3_mined', '상법 보험편, 보험업감독규정', 'ai_draft', 'medium', 'admin'),
  ('term', '단체보험의 피보험자 동의와 규약', '단체가 규약에 따라 구성원의 전부 또는 일부를 피보험자로 하는 단체보험을 체결하는 경우, 개별 피보험자의 서면동의를 갈음할 수 있다(상법 제735조의3). 다만 규약이 없거나 구성원이 아닌 단체·사용자를 수익자로 하는 사망보험 등은 피보험자의 서면동의가 필요할 수 있다.', '계약청약고지', array['단체보험 동의','규약','피보험자 서면동의 갈음','단체 사망보험','수익자'], 'cycle3_mined', 'cycle3_mined', '상법 제735조의3', 'ai_draft', 'medium', 'admin'),
  ('term', '연금소득 분리과세 한도(연 1,500만원)', '세제적격 연금계좌(연금저축·IRP 등)에서 연금형태로 수령한 과세대상 사적연금소득이 연간 1,500만원 이하이면 3.3~5.5%의 저율 분리과세가 적용된다. 1,500만원을 초과하면 전액 종합과세 또는 16.5% 분리과세 중 납세자에게 유리한 방식을 선택할 수 있다. 분리과세 기준금액은 2024년부터 종전 1,200만원에서 1,500만원으로 상향되었다.', '세제과세', array['연금소득 분리과세','1500만원','사적연금','종합과세 기준','연금 세금'], 'cycle3_mined', 'cycle3_mined', '소득세법 제14조·제64조의4(연금소득 분리과세)', 'ai_draft', 'high', 'admin'),
  ('term', '연금소득세 원천징수 세율(3~5% 연령별)', '세제적격 연금계좌에서 연금을 수령하면 수령 시 연령에 따라 70세 미만 5%, 70~79세 4%, 80세 이상 3%의 원천징수세율이 적용된다(지방소득세 포함 시 각각 5.5%·4.4%·3.3%). 종신형 연금은 일반적으로 4%(지방세 포함 4.4%)가 적용된다. 연령이 높을수록 세부담이 낮아지는 구조다.', '세제과세', array['연금소득세율','연령별 세율','원천징수','3~5%','종신연금 세율'], 'cycle3_mined', 'cycle3_mined', '소득세법 제129조(원천징수세율)', 'ai_draft', 'high', 'admin'),
  ('term', '연금저축 중도해지 기타소득세(16.5%)', '세액공제를 받은 연금저축을 연금 외의 형태로 중도해지·인출하면 세액공제받은 납입원금과 운용수익에 대해 16.5%(지방소득세 포함)의 기타소득세가 분리과세로 부과된다. 다만 부득이한 사유에 해당하면 16.5%가 아닌 저율의 연금소득세로 과세된다.', '세제과세', array['연금저축 해지','기타소득세','16.5%','세액공제 환수','중도인출 세금'], 'cycle3_mined', 'cycle3_mined', '소득세법 제21조·제129조(기타소득 원천징수)', 'ai_draft', 'high', 'admin'),
  ('term', '부득이한 사유 연금외수령 저율과세', '가입자의 사망·해외이주, 천재지변, 가입자·부양가족의 3개월 이상 요양, 가입자 파산·개인회생, 연금계좌 취급기관 영업정지 등 부득이한 사유로 연금 외 인출 시 16.5% 기타소득세가 아닌 저율의 연금소득세로 분리과세된다. 사유 확인서류는 사유 발생일부터 6개월 이내에 연금계좌 취급자에게 제출해야 한다.', '세제과세', array['부득이한 사유','연금외수령','저율과세','중도인출 예외','요양 인출'], 'cycle3_mined', 'cycle3_mined', '소득세법 시행령 제20조의2(부득이한 사유)', 'ai_draft', 'high', 'admin'),
  ('term', '보험금 상속세 비과세 한도(피보험자=계약자)', '피상속인이 보험료를 부담한 생명보험·손해보험의 사망보험금은 상속재산으로 보아 상속세가 과세되나, 상속인이 받는 금융재산(보험금 포함)은 순금융재산의 20%(2천만원~최대 2억원)를 금융재산 상속공제로 공제받을 수 있다. 보험료를 누가 부담했는지가 간주상속재산 과세 판단의 핵심이다.', '세제과세', array['사망보험금 상속세','간주상속재산','금융재산 상속공제','보험료 부담자','상속세 비과세'], 'cycle3_mined', 'cycle3_mined', '상속세 및 증여세법 제8조·제22조', 'ai_draft', 'medium', 'admin'),
  ('term', '계약자·수익자 분리 설계 절세(상속세 비과세 구조)', '계약자=보험료 납부자, 피보험자=피상속인, 수익자=상속인으로 설계하고 계약자가 자기 소득으로 보험료를 실제 납부했음을 증빙하면, 수령 보험금이 피상속인의 상속재산에 포함되지 않을 수 있다. 다만 보험료 자금출처가 피상속인이면 간주상속재산으로 보아 상속세가 과세된다.', '세제과세', array['계약자 수익자 분리','상속세 절세','보험 가입설계','자금출처','간주상속'], 'cycle3_mined', 'cycle3_mined', '상속세 및 증여세법 제8조, 국세청 상속세 해설', 'ai_draft', 'medium', 'admin'),
  ('term', '계약자 변경과 증여세 과세시기', '보험계약 도중 계약자를 자녀 등으로 변경하면 변경 시점이 아니라 향후 보험금·해지환급금 수령 시점에 그동안 부모가 납부한 보험료 상당액이 증여로 과세될 수 있다. 변경 이후 자녀가 자기 자금으로 납입한 보험료는 증여 대상에서 제외된다.', '세제과세', array['계약자 변경 증여세','보험료 부담','증여 과세시기','명의변경','자녀 보험'], 'cycle3_mined', 'cycle3_mined', '상속세 및 증여세법 제34조, 국세청 예규', 'ai_draft', 'medium', 'admin'),
  ('term', '비과세종합저축 보험(노인·장애인 한도 5천만원)', '만 65세 이상 거주자, 장애인복지법상 장애인, 국가유공자 등 가입대상자가 1인당 원금 5,000만원 한도로 비과세종합저축에 가입하면 이자·배당소득에 세금이 면제된다. 저축성보험도 비과세종합저축으로 가입할 수 있으며 전 금융기관 합산 한도가 적용된다.', '세제과세', array['비과세종합저축','노인 비과세','장애인 비과세','5천만원 한도','이자소득 면제'], 'cycle3_mined', 'cycle3_mined', '조세특례제한법 제88조의2(비과세종합저축)', 'ai_draft', 'high', 'admin'),
  ('term', '저축성보험 비과세 10년 유지 중 중도인출 영향', '10년 비과세 요건을 적용받는 저축성보험은 유지 기간 중 일부를 중도인출하더라도 계약이 해지되지 않고 유지되면 비과세 판단은 최종 수령 시점 기준으로 이뤄진다. 다만 월적립식 비과세 한도 계약은 인출 시 매월 균등납입 요건 위반 여부를 별도로 점검해야 한다.', '세제과세', array['저축성보험 중도인출','비과세 유지','10년 요건','균등납입','부분인출'], 'cycle3_mined', 'cycle3_mined', '소득세법 시행령 제25조, 국세청 해석사례', 'ai_draft', 'medium', 'admin'),
  ('term', '즉시연금 상속형·종신형 과세 차이', '즉시연금 중 종신형은 비과세 요건을 충족하면 연금소득이 비과세되나, 상속형(만기 후 원금 상환형)은 일시납 비과세 한도(1인당 1억원)를 초과하는 보험차익이 과세 대상이 될 수 있다. 가입 목적과 수령방식에 따라 비과세 여부가 갈리므로 가입 전 과세구조 확인이 필요하다.', '세제과세', array['즉시연금 과세','상속형 종신형','비과세 차이','1억원 한도','보험차익'], 'cycle3_mined', 'cycle3_mined', '소득세법 시행령 제25조, 국세청 해석', 'ai_draft', 'medium', 'admin'),
  ('term', '퇴직소득 IRP 이연 시 과세이연(이연퇴직소득)', '퇴직금을 IRP 등 연금계좌로 이전(지급일부터 60일 이내)하면 퇴직소득세 원천징수가 이연되고, 향후 연금으로 수령하면 연금 실제 수령연차 10년 이하 구간은 이연퇴직소득세의 70%, 10년 초과 구간은 60%만 부담하는 연금소득세로 분리과세된다. 일시금 수령보다 세부담이 줄어드는 구조다.', '세제과세', array['퇴직소득 과세이연','이연퇴직소득','IRP 이전','60일','연금수령 30% 감면'], 'cycle3_mined', 'cycle3_mined', '소득세법 제146조·제147조(퇴직소득 과세이연)', 'ai_draft', 'high', 'admin'),
  ('term', '장애인전용 보장성보험 세액공제(연 100만원·16.5%)', '기본공제대상자 중 장애인을 피보험자 또는 수익자로 하는 장애인전용 보장성보험은 일반 보장성보험과 별도로 연 100만원 한도에서 15%(지방소득세 포함 16.5%) 세액공제를 받는다. 일반 보장성보험(연 100만원·12%) 공제와 중복 적용이 가능하다.', '세제과세', array['장애인전용 보장성보험','세액공제','16.5%','장애인 보험 공제','별도 한도'], 'cycle3_mined', 'cycle3_mined', '소득세법 제59조의4 제1항', 'ai_draft', 'high', 'admin'),
  ('term', '장애인을 수익자로 한 보험금 증여세 비과세(연 4천만원)', '장애인복지법에 따라 등록한 장애인을 보험금 수령인(수익자)으로 하는 보험에서 장애인이 받는 보험금은 연간 4,000만원 한도로 증여세가 비과세된다. 비과세 대상은 보험료 납입액이 아니라 보험사고 발생 시 실제 수령하는 보험금 기준이며, 세법상 장애인 요건을 충족해야 한다.', '세제과세', array['장애인 보험금 증여세','4천만원 비과세','장애인 수익자','증여세 비과세','장애인 지원'], 'cycle3_mined', 'cycle3_mined', '상속세 및 증여세법 제46조 제8호', 'ai_draft', 'high', 'admin'),
  ('term', 'ISA 만기자금 연금계좌 전환 추가공제(최대 300만원)', '개인종합자산관리계좌(ISA) 만기 시 자금을 60일 이내 연금계좌로 이체하면 이체금액의 10%(최대 300만원)를 연금계좌 세액공제 한도에 추가로 공제받을 수 있다. 기존 연금저축 600만원·IRP 합산 900만원 한도와 별도로 적용되는 세제혜택이다.', '세제과세', array['ISA 연금 전환','추가 세액공제','300만원','만기자금 이체','연금계좌 전환'], 'cycle3_mined', 'cycle3_mined', '조세특례제한법 제91조의18·소득세법 제59조의3', 'ai_draft', 'medium', 'admin'),
  ('term', '보험차익 이자소득세 원천징수(15.4%)', '비과세 요건을 충족하지 못한 저축성보험의 보험차익은 이자소득으로 보아 15.4%(소득세 14% + 지방소득세 1.4%)가 원천징수된다. 만기·해지 시 보험금에서 납입보험료를 뺀 차익이 과세표준이 되며, 금융소득종합과세 대상에도 합산된다.', '세제과세', array['보험차익 이자소득세','15.4%','원천징수','저축성보험 과세','과세표준'], 'cycle3_mined', 'cycle3_mined', '소득세법 제16조·제129조(이자소득 원천징수)', 'ai_draft', 'high', 'admin'),
  ('term', '연금저축계좌 간 이체(과세이연 유지)', '연금저축보험·연금저축펀드·연금저축신탁 상호 간 또는 다른 금융기관 연금계좌로 자금을 계좌이체 방식으로 이전하면 인출로 보지 않아 기타소득세가 부과되지 않고 과세이연이 유지된다. 단 이체 요건과 절차(계좌이체 방식)를 준수해야 과세 없이 이전된다.', '세제과세', array['연금저축 이체','과세이연 유지','계좌이체','연금계좌 이전','비과세 이전'], 'cycle3_mined', 'cycle3_mined', '소득세법 시행령 제40조의4(연금계좌의 이체)', 'ai_draft', 'high', 'admin'),
  ('term', '변액보험 보험차익 비과세(저축성 요건 동일)', '변액유니버셜·변액연금 등 변액보험도 저축성보험에 해당하면 10년 이상 유지·납입한도 등 비과세 요건을 충족할 경우 펀드 운용수익을 포함한 보험차익이 비과세된다. 일반 펀드(배당소득 15.4% 과세)와 달리 비과세가 가능한 점이 변액보험의 세제 차별점이다.', '세제과세', array['변액보험 비과세','보험차익','펀드 운용수익','저축성 요건','10년 유지'], 'cycle3_mined', 'cycle3_mined', '소득세법 시행령 제25조(저축성보험의 보험차익)', 'ai_draft', 'high', 'admin'),
  ('term', '사망보험금 연금형 수령 시 평가(유기정기금 평가)', '사망보험금을 일시금이 아닌 연금형으로 분할 수령할 경우, 상속·증여재산 평가 시 정기금(연금)의 현재가치로 평가한다. 매년 받을 금액에 기획재정부 고시 이자율(3%)을 적용해 현재가치를 산정하므로 일시금 평가와 세액 차이가 발생할 수 있다.', '세제과세', array['연금형 보험금 평가','유기정기금','현재가치 평가','정기금 평가율','상속세 평가'], 'cycle3_mined', 'cycle3_mined', '상속세 및 증여세법 시행령 제62조(정기금의 평가)', 'ai_draft', 'medium', 'admin'),
  ('term', '보험계약 상속 시 해약환급금 평가', '피상속인이 계약자·납입자였던 미수령 보험계약을 상속할 경우, 상속개시일 현재 해약환급금 상당액을 상속재산으로 평가한다. 향후 만기·사망보험금이 아니라 상속개시 시점의 해약환급금이 평가 기준이 되는 점이 실무 핵심이다.', '세제과세', array['보험계약 상속','해약환급금 평가','상속재산 평가','상속개시일','미수령 계약'], 'cycle3_mined', 'cycle3_mined', '상속세 및 증여세법 시행령 제62조', 'ai_draft', 'medium', 'admin'),
  ('term', '비거주자 연금소득 원천징수와 조세조약', '비거주자가 국내 연금계좌에서 연금을 수령하면 국내세법상 원천징수가 이뤄지나, 거주지국과 체결한 조세조약상 연금 조항이 우선 적용될 수 있다. 해외이주자가 연금을 수령할 때 제한세율·과세권 배분을 조세조약으로 확인해야 한다.', '세제과세', array['비거주자 연금소득','조세조약','원천징수','해외이주 연금','제한세율'], 'cycle3_mined', 'cycle3_mined', '소득세법 제156조, 한국 조세조약', 'ai_draft', 'medium', 'admin'),
  ('term', '연금계좌 사망 시 상속인 승계와 과세', '연금계좌 가입자가 사망하면 배우자 등 상속인이 계좌를 승계해 본인 연금계좌로 전환할 수 있으며, 이 경우 연금형 수령으로 과세이연이 유지된다. 승계하지 않고 해지하면 연금외수령으로 기타소득세가 과세되므로 승계 여부에 따라 세부담이 달라진다.', '세제과세', array['연금계좌 상속','상속인 승계','과세이연 승계','배우자 연금 승계','사망 시 연금'], 'cycle3_mined', 'cycle3_mined', '소득세법 시행령 제40조의2(연금계좌)', 'ai_draft', 'medium', 'admin'),
  ('term', '퇴직연금 DC형 추가납입 세액공제', '확정기여형(DC) 퇴직연금에 가입자가 회사 부담금 외에 본인이 추가로 납입한 금액은 연금계좌 세액공제 한도(IRP 합산 900만원) 내에서 세액공제 대상이 된다. 추가납입분은 운용수익과 함께 과세이연되며 연금 수령 시 연금소득세가 적용된다.', '세제과세', array['DC형 추가납입','퇴직연금 세액공제','본인부담금','900만원 한도','추가납입'], 'cycle3_mined', 'cycle3_mined', '근로자퇴직급여보장법·소득세법 제59조의3', 'ai_draft', 'medium', 'admin'),
  ('term', '연금외수령 시 운용수익·세액공제분만 과세', '연금계좌를 연금 외로 인출할 때 과세 대상은 세액공제를 받은 납입원금과 운용수익이며, 세액공제를 받지 않은 납입원금(한도 초과납입분 등)은 비과세로 먼저 인출된 것으로 본다. 따라서 인출 순서에 따라 과세금액이 달라진다.', '세제과세', array['연금외수령 과세','인출 순서','세액공제분 과세','비과세 원금','운용수익 과세'], 'cycle3_mined', 'cycle3_mined', '소득세법 시행령 제40조의3(연금계좌 인출순서)', 'ai_draft', 'high', 'admin'),
  ('term', '보험금 비과세 소득(보장성보험의 보험금)', '사망·상해·질병·자산손해 등 보장성보험에서 받는 보험금은 소득세법상 과세대상 소득이 아니어서 소득세가 부과되지 않는다. 다만 계약구조에 따라 상속세·증여세가 별도로 문제될 수 있어 소득세 비과세와 상속·증여세 과세는 구분해 판단해야 한다.', '세제과세', array['보장성 보험금 비과세','소득세 비과세','보험금 세금','상속증여세 구분','보험금 소득'], 'cycle3_mined', 'cycle3_mined', '소득세법 제4조·제12조(비과세소득)', 'ai_draft', 'high', 'admin'),
  ('term', '연금계좌 세액공제 이월(납입연도 전환특례)', '한 해 연금계좌 납입액 중 세액공제를 받지 못한 금액은 다음 연도 이후 납입액으로 전환해 세액공제를 신청할 수 있다(납입연도 전환특례). 한도 초과로 공제받지 못한 납입분을 향후 공제로 활용할 수 있는 제도다.', '세제과세', array['연금계좌 세액공제 이월','납입연도 전환특례','초과납입 활용','공제 이월','연금저축'], 'cycle3_mined', 'cycle3_mined', '소득세법 시행령(연금계좌 전환특례)', 'ai_draft', 'medium', 'admin'),
  ('term', '비례재보험 종류 — 비례할당재보험(Quota Share)', '비례재보험의 한 형태로, 출재사가 인수한 모든 대상 계약에 대해 보험가입금액·보험료·발생손해를 사전에 약정한 동일 비율로 출재사와 수재사가 나누어 부담하는 방식이다. 예컨대 60% 출재 약정이면 보험료의 60%를 수재사에 넘기고 손해의 60%를 수재사가 보상한다. 운영이 단순하고 신설·소규모 보험사의 인수능력 확충에 활용되나, 우량물건도 동일 비율로 출재되어 출재사의 출재 효율은 낮은 편이다.', '재보험', array['비례할당재보험','Quota Share','비례재보험','출재비율','위험분산'], 'cycle3_mined', 'cycle3_mined', '보험연구원 재보험 연구보고서 nre2019-1212 (kiri.or.kr) / KiRi Weekly 2012.6.18 손해보험의 이해6 위험의 보유와 재보험 (kiri.or.kr)', 'ai_draft', 'high', 'admin'),
  ('term', '비례재보험 종류 — 초과액재보험(Surplus)', '출재사가 자기보유한도(line)를 먼저 정하고, 보유한도를 초과하는 금액 부분만 약정 배수(line 수) 범위 내에서 수재사에 출재하는 비례재보험 방식이다. 보유한도 이내의 소액·우량 계약은 출재하지 않고 보유할 수 있어 비례할당재보험(Quota Share)보다 출재사의 보유 정책을 정교하게 운영할 수 있다. 계약별로 출재비율이 달라지므로 사무 처리가 비례할당보다 복잡하다.', '재보험', array['초과액재보험','Surplus','비례재보험','보유한도','line'], 'cycle3_mined', 'cycle3_mined', '보험연구원 재보험 연구보고서 nre2019-1212 (kiri.or.kr) / KiRi Weekly 2012.6.18 손해보험의 이해6 (kiri.or.kr)', 'ai_draft', 'high', 'admin'),
  ('term', '비비례재보험(Non-proportional Reinsurance)', '보험료와 책임을 비율로 나누지 않고, 손해가 출재사가 정한 일정 금액(또는 손해율)을 초과하는 경우에만 수재사가 초과분을 보상하는 재보험 방식의 총칭이다. 손해액 기준의 초과손해액재보험(XL)과 손해율 기준의 초과손해율재보험(Stop Loss)이 대표 유형이다. 비례재보험과 달리 거대·이상 손해에 대한 방어가 목적이며, 통상 손해 발생 규모를 예측해 재보험료를 산출한다.', '재보험', array['비비례재보험','Non-proportional','초과손해액','초과손해율','거대위험'], 'cycle3_mined', 'cycle3_mined', '보험연구원 재보험 연구보고서 nre2019-1212 (kiri.or.kr) / 위키백과 재보험 (ko.wikipedia.org)', 'ai_draft', 'high', 'admin'),
  ('term', '초과손해율재보험(Stop Loss)', '일정 기간(통상 1년) 동안 출재사가 인수한 특정 보험종목의 누적 손해율이 사전에 약정한 손해율(예: 110%)을 초과하면, 초과 손해율에 해당하는 손해를 수재사가 일정 한도까지 보상하는 비비례재보험 방식이다. 개별 사고가 아니라 연간 손해율 변동(영업 실적의 이상 악화)을 방어하는 데 목적이 있으며, 농작물보험 등 손해율 변동성이 큰 종목에 활용된다. 초과손해액재보험(XL)이 ''손해액'' 기준인 것과 달리 ''손해율'' 기준인 점이 핵심 차이다.', '재보험', array['초과손해율재보험','Stop Loss','비비례재보험','손해율','연간손해방어'], 'cycle3_mined', 'cycle3_mined', '보험연구원 재보험 연구보고서 nre2019-1212 (kiri.or.kr) / KiRi Weekly 손해보험의 이해6 (kiri.or.kr)', 'ai_draft', 'high', 'admin'),
  ('term', '누적초과손해액재보험(Catastrophe XL, Cat XL)', '한 건의 거대재해(태풍·지진·홍수 등)로 인해 다수의 보험계약에서 동시에 발생한 손해를 합산하여, 그 누적 손해액이 출재사의 보유한도를 초과하는 부분을 수재사가 보상하는 초과손해액재보험의 한 형태다. 단일 위험(Risk XL)이 한 계약·한 사고를 대상으로 하는 것과 달리, 하나의 재해 사건(event)으로 인한 다수 손해의 집적(누적)을 방어한다. 위험집중 관리와 지급여력 보호의 핵심 수단이다.', '재보험', array['누적초과손해액','Cat XL','거대재해','위험집중','event'], 'cycle3_mined', 'cycle3_mined', '보험연구원 재보험 연구보고서 nre2019-1212 (kiri.or.kr) / 코리안리 인슈어런스월드 글로벌 CAT Bond 발행동향 (koreanre.co.kr)', 'ai_draft', 'high', 'admin'),
  ('term', '출재수수료(Ceding Commission)', '비례재보험에서 수재사가 출재사에게 지급하는 수수료로, 출재사가 보험계약 모집·발행·유지에 들인 사업비(모집수수료·계약관리비 등)를 보전해 주는 성격이다. 수재사가 받는 출재보험료의 일정 비율로 정해지며, 출재 물건의 질·손해 경험에 따라 협상으로 결정된다. 출재사 입장에서는 출재보험료 지출을 일부 회수하는 효과가 있어 재보험의 실질 비용을 낮춘다.', '재보험', array['출재수수료','Ceding Commission','비례재보험','재보험수수료','사업비보전'], 'cycle3_mined', 'cycle3_mined', '보험연구원 재보험 연구보고서 nre2019-1212 (kiri.or.kr) / 재보험 출재비율 최적화 전략연구 (한국보험학회지, KCI ART002076236)', 'ai_draft', 'high', 'admin'),
  ('term', '이익수수료(Profit Commission)', '비례재보험 특약에서 수재사가 해당 출재물건으로 이익(수재보험료가 지급보험금·비용을 초과)을 본 경우, 그 이익의 일부를 출재사에게 환원해 지급하는 수수료다. 출재사가 우량한 물건을 출재하도록 유인하고 출재사·수재사 간 손익을 공유하는 장치로, 약정 기간의 손해 경험을 정산하여 사후적으로 산정된다. 생명보험 재보험 거래에서 보험료 할인방식과 함께 자주 쓰이는 비례재보험 정산 방식이다.', '재보험', array['이익수수료','Profit Commission','비례재보험','손익공유','재보험정산'], 'cycle3_mined', 'cycle3_mined', '보험연구원 재보험 연구보고서 nre2019-1212 (kiri.or.kr) / 재보험 출재비율 최적화 전략연구 (한국보험학회지, KCI ART002076236)', 'ai_draft', 'medium', 'admin'),
  ('term', '재재보험(Retrocession)', '재보험을 인수한 수재사(재보험사)가 인수한 위험의 전부 또는 일부를 다시 다른 재보험사에게 출재(전가)하는 거래다. 위험을 넘겨받는 측을 재재보험자(retrocessionaire)라 한다. 재보험사 자신의 인수능력 한계를 넘는 거대위험을 추가 분산하고 위험집중을 완화하기 위해 이용하며, 이를 통해 글로벌 보험위험이 여러 단계로 분산된다.', '재보험', array['재재보험','Retrocession','위험재분산','재보험사','수재'], 'cycle3_mined', 'cycle3_mined', '보험연구원 재보험 연구보고서 nre2019-1212 (kiri.or.kr) / 위키백과 재보험 (ko.wikipedia.org)', 'ai_draft', 'high', 'admin'),
  ('term', '공동재보험(Coinsurance, 재보험 형태)', '출재사가 보험위험뿐 아니라 금리위험·해약위험 등 다른 위험까지 함께 수재사에게 이전하는 재보험 방식으로, 위험보험료뿐 아니라 저축보험료 등 보험료의 일정 비율을 함께 출재하고 대응 자산도 이전한다. 금융위원회가 IFRS17·K-ICS 도입에 대비한 재무구조(보험부채) 개선 수단으로 도입방안을 발표하면서(2020년 1월 30일) 국내 제도화되었으며, 기존 위험보험료만 출재하던 전통 재보험과 구별된다.', '재보험', array['공동재보험','Coinsurance','금리위험전가','KICS','재무구조개선'], 'cycle3_mined', 'cycle3_mined', '금융위원회 보도자료 ''공동재보험(Coinsurance) 도입방안'' 2020.1.30 (fsc.go.kr / korea.kr newsId 156373377) / 보험업감독규정 변경예고', 'ai_draft', 'high', 'admin'),
  ('term', '수정공동재보험(Modified Coinsurance, Modco)', '공동재보험과 유사하게 출재사가 보험위험과 금리위험 등을 수재사에 이전하되, 대응하는 운용자산은 출재사가 그대로 보유하고 책임준비금(부채)만 수재사로 이전하는 변형 방식이다. 출재사가 자산 운용권을 유지하는 점이 자산까지 넘기는 공동재보험과의 핵심 차이로, 자산운용 정책·세무·회계상 이유로 선택된다. 금융위원회 공동재보험 도입방안에서 함께 소개되었다.', '재보험', array['수정공동재보험','Modco','책임준비금이전','자산보유','공동재보험'], 'cycle3_mined', 'cycle3_mined', '금융위원회 보도자료 ''공동재보험(Coinsurance) 도입방안'' 2020.1. (fsc.go.kr / korea.kr) / 보험업감독규정 변경예고', 'ai_draft', 'medium', 'admin'),
  ('term', '대재해채권(Cat Bond, 보험연계증권)', '보험사·재보험사가 인수한 지진·태풍 등 거대재해 위험을 자본시장 투자자에게 채권 형태로 전가하는 보험연계증권(ILS)의 대표 상품이다. 약정한 재해(트리거)가 발생하면 원리금 상환이 일부·전부 면제되어 발행자의 손실을 보전하고, 미발생 시 투자자는 높은 이자를 받는다. 최초 성공적 발행은 1994년 하노버리(Hannover Re)이며, 한국은 금융위원회가 2014년 7월 규제완화 방안에 도입 검토를 포함했다. 재보험 인수능력을 초과하는 위험을 자본시장으로 분산하는 보완 수단이다.', '재보험', array['대재해채권','Cat Bond','보험연계증권','ILS','거대재해전가'], 'cycle3_mined', 'cycle3_mined', '보험연구원 KiRi Weekly 2013.2.12 대체투자수단으로서 대재해채권 (kiri.or.kr) / 보험연구원 연구보고서 RE0002 대재해채권 (kiri.or.kr) / 금융위원회 2014.7 규제완화방안', 'ai_draft', 'medium', 'admin'),
  ('term', '보험연계증권(ILS, Insurance-Linked Securities)', '보험·재보험사가 인수한 보험위험(특히 자연재해 등 거대위험)을 증권 형태로 자본시장에 전가하는 금융상품의 총칭으로, 대재해채권(Cat Bond)이 대표적이다. 보험위험과 자본시장 수익을 연계하여 전통 재보험을 보완하는 대체위험전가(ART) 수단이며, 보험 손해와 주식·금리 시장의 상관관계가 낮아 투자자에게 분산투자 효과를 제공한다.', '재보험', array['보험연계증권','ILS','대체위험전가','ART','대재해채권'], 'cycle3_mined', 'cycle3_mined', '보험연구원 연구보고서 RE0002 대재해채권(Cat Bond) (kiri.or.kr) / 코리안리 인슈어런스월드 글로벌 CAT Bond (koreanre.co.kr)', 'ai_draft', 'medium', 'admin'),
  ('term', '대체위험전가(ART, Alternative Risk Transfer)', '전통적 재보험 외의 방법으로 보험위험을 분산·전가하는 기법의 총칭으로, 대재해채권(Cat Bond)·보험연계증권(ILS)·캡티브(전속 보험회사)·날씨파생상품 등이 포함된다. 재보험 시장의 인수능력이 부족하거나 비용이 높을 때 자본시장·금융기법을 활용해 거대위험을 분산하는 보완 수단이며, 보험위험을 자본시장 위험과 연계하는 것이 특징이다.', '재보험', array['대체위험전가','ART','캡티브','날씨파생','보험연계증권'], 'cycle3_mined', 'cycle3_mined', '보험연구원 연구보고서 RE0002 대재해채권 (kiri.or.kr) / 보험연구원 KiRi Weekly 대재해채권 (kiri.or.kr)', 'ai_draft', 'medium', 'admin'),
  ('term', '의무재보험 vs 임의재보험(자동출재·건별협의 구분)', '임의재보험(Facultative)은 출재가 필요한 개별 계약마다 출재사가 제의하고 수재사가 인수 여부를 자유롭게 결정하는 방식인 반면, 특약재보험(Treaty)은 사전 약정 범위에 해당하는 계약이 자동으로 출재·인수되어 ''의무적'' 성격을 갖는다. 즉 임의재보험은 출재·수재 모두 임의이고, 특약재보험은 약정 범위 내에서 출재사도 자동 출재하고 수재사도 자동 인수해야 하는 점이 핵심 구별이다.', '재보험', array['의무재보험','임의재보험','특약재보험','자동출재','Facultative'], 'cycle3_mined', 'cycle3_mined', '위키백과 재보험 (ko.wikipedia.org) / 보험연구원 재보험 연구보고서 nre2019-1212 (kiri.or.kr)', 'ai_draft', 'high', 'admin'),
  ('term', '위험전가 효과 없는 재보험(금융재보험·Finite Reinsurance)', '형식은 재보험계약이나 실질적으로 보험위험을 거의 이전하지 않고 재무·회계상 효과(이익 평준화, 자본 보강 등)를 주된 목적으로 하는 재보험을 말한다. 보험위험의 유의적 이전이 없으면 보험회계상 재보험으로 인식할 수 없고 예치금(금융거래)으로 처리해야 한다. 보험업감독규정·시행세칙의 재보험관리기준은 위험전가 효과의 판단과 위험전가 효과가 없는 재보험의 회계처리를 규율한다.', '재보험', array['금융재보험','Finite','위험전가효과','예치금처리','재보험관리기준'], 'cycle3_mined', 'cycle3_mined', '보험업감독규정 및 보험업감독업무시행세칙 재보험관리기준 (국가법령정보센터 law.go.kr)', 'ai_draft', 'medium', 'admin'),
  ('term', '재보험관리기준(보험업감독규정상)', '보험회사가 건전한 재보험 거래를 위해 수립·운영해야 하는 내부 관리 기준으로, 보험업감독규정 및 시행세칙(재보험 관련 별표)에 근거한다. 자기보유한도와 자동인수한도의 설정, 출재 한도와 출재처(수재사) 선정, 위험전가 효과의 판단, 위험전가 효과가 없는 재보험의 회계처리 등을 포함한다. 금융감독원은 이 기준 준수 여부를 감독한다.', '재보험', array['재보험관리기준','보험업감독규정','자기보유한도','출재한도','금융감독원'], 'cycle3_mined', 'cycle3_mined', '보험업감독규정 (금융위원회 고시) 및 보험업감독업무시행세칙 재보험관리기준 (국가법령정보센터 law.go.kr)', 'ai_draft', 'medium', 'admin'),
  ('term', '국내 재보험사 시장구조 — 코리안리와 국내우선출재제도 폐지', '코리안리재보험은 1963년 대한손해재보험공사로 출범, 1978년 대한재보험으로 민영화, 2002년 코리안리재보험으로 사명을 변경한 국내 유일의 전업 재보험사다. 국내에서 발생한 재보험 물량을 우선 출재하도록 한 국내우선출재제도로 독점적 지위를 가졌으나, 1993~1997년에 걸쳐 동 제도가 폐지되고 1997년 재보험 시장 자유화로 해외 재보험사가 진입하면서 경쟁 구조로 전환되었다. 출재사는 국내·외 다수 재보험사 중에서 출재처를 선택할 수 있다.', '재보험', array['코리안리','대한재보험','국내우선출재','재보험시장','재보험사'], 'cycle3_mined', 'cycle3_mined', '코리안리재보험 (ko.wikipedia.org / encykorea.aks.ac.kr E0015175) / 한국공제보험신문 재보험사 탐방① (kongje.or.kr)', 'ai_draft', 'high', 'admin'),
  ('term', '수재(受再)와 수재보험료', '수재는 재보험사(수재사)가 출재사로부터 보험위험을 넘겨받아 인수하는 행위로, 출재(出再)의 반대 개념이다. 이때 수재사가 받는 보험료를 수재보험료라 하며, 수재사는 그 대가로 약정 범위의 손해를 보상할 책임을 진다. 손해보험·생명보험 모두에서 출수재(出受再) 업무가 이루어지며, 한 회사가 출재와 수재를 동시에 수행하기도 한다.', '재보험', array['수재','수재보험료','출수재','재보험인수','수재사'], 'cycle3_mined', 'cycle3_mined', '코리안리재보험 사업영역 (encykorea.aks.ac.kr E0015175) / 보험연구원 재보험 연구보고서 nre2019-1212 (kiri.or.kr)', 'ai_draft', 'high', 'admin'),
  ('term', '위험보험료재보험(생명보험 비례재보험)', '생명보험에서 사망보장 등 위험보장 부분의 위험보험료만을 대상으로 출재하는 비례재보험 방식으로, 저축보험료나 자산은 이전하지 않는다. 위험률 변동 위험을 분산하는 전통적 생명보험 재보험 형태이며, 금리위험·자산까지 함께 넘기는 공동재보험(Coinsurance)과 구별된다. 생명보험 재보험 거래에서 이익수수료방식·보험료할인방식과 함께 운영된다.', '재보험', array['위험보험료재보험','생명보험재보험','위험률','비례재보험','공동재보험'], 'cycle3_mined', 'cycle3_mined', '금융위원회 보도자료 공동재보험 도입방안 2020.1. (fsc.go.kr) / 보험연구원 재보험 연구보고서 nre2019-1212 (kiri.or.kr)', 'ai_draft', 'medium', 'admin'),
  ('term', '재보험 보유와 출재의 비용·자본 트레이드오프', '보험사가 위험을 자기보유하면 손해 변동성과 그에 따른 자본(지급여력) 부담이 커지고, 출재하면 출재보험료 비용이 발생하는 상충관계가 있다. 따라서 재보험 비용과 자본비용의 합을 최소화하는 지점에서 최적 출재비율을 결정하는 것이 출재 전략의 핵심이다. 보유한도가 높을수록 자본 부담이, 출재비율이 높을수록 비용 부담이 커지므로 양자의 균형이 중요하다.', '재보험', array['최적출재비율','자본비용','재보험비용','보유전략','지급여력'], 'cycle3_mined', 'cycle3_mined', '재보험 출재비율 최적화 전략연구 (한국보험학회지 보험학회지, KCI ART002076236) / KiRi Weekly 2012.6.18 위험의 보유와 재보험 (kiri.or.kr)', 'ai_draft', 'medium', 'admin'),
  ('term', '재보험의 기능 — 인수능력 확충(Capacity)', '재보험의 핵심 기능 중 하나로, 보험사가 자기자본·지급여력만으로는 인수하기 어려운 대형·고액 계약을 재보험을 통해 위험을 분산함으로써 인수할 수 있게 해주는 효과다. 출재를 전제로 자기보유한도를 초과하는 부분까지 인수가 가능해져 영업 규모를 확대할 수 있다. 위험분산·실적안정·거대위험 방어와 함께 재보험의 대표 기능으로 꼽힌다.', '재보험', array['인수능력','Capacity','재보험기능','위험분산','대형계약'], 'cycle3_mined', 'cycle3_mined', '보험연구원 재보험 연구보고서 nre2019-1212 (kiri.or.kr) / KiRi Weekly 2012.6.18 위험의 보유와 재보험 (kiri.or.kr)', 'ai_draft', 'medium', 'admin'),
  ('term', '재보험의 기능 — 경영실적 안정화(Stabilization)', '재보험은 거대·이상 손해 발생 시 손해의 일부를 수재사가 보상하게 함으로써 출재사의 연도별 손해율 변동을 완화하고 경영실적을 평준화하는 기능을 한다. 특히 초과손해율재보험(Stop Loss)은 연간 손해율이 약정 수준을 넘는 부분을 방어하여 실적 안정에 직접 기여한다. 인수능력 확충·거대위험 방어와 함께 재보험의 주요 효익이다.', '재보험', array['실적안정화','Stabilization','손해율평준화','Stop Loss','재보험기능'], 'cycle3_mined', 'cycle3_mined', '보험연구원 재보험 연구보고서 nre2019-1212 (kiri.or.kr) / KiRi Weekly 2012.6.18 위험의 보유와 재보험 (kiri.or.kr)', 'ai_draft', 'medium', 'admin'),
  ('term', '원수보험사(원보험사)와 재보험의 관계', '원수보험사(원보험사)는 보험계약자와 직접 보험계약을 체결하고 보험금 지급책임을 지는 보험회사로, 인수한 위험의 일부를 재보험사에 출재한다. 보험계약자는 원수보험사에만 보험금을 청구하며, 재보험은 원수보험사와 재보험사 사이의 별도 계약일 뿐 계약자와 재보험사 사이에는 직접 권리·의무 관계가 없다. 따라서 재보험 출재 여부와 무관하게 보험금 지급책임은 원수보험사가 진다.', '재보험', array['원수보험사','원보험사','재보험사','보험금지급책임','출재'], 'cycle3_mined', 'cycle3_mined', '위키백과 재보험 (ko.wikipedia.org) / 보험연구원 재보험 연구보고서 nre2019-1212 (kiri.or.kr)', 'ai_draft', 'high', 'admin'),
  ('term', '재보험과 보험계약자의 관계(직접 권리 부존재 원칙)', '재보험은 원수보험사(출재사)와 재보험사(수재사) 사이의 계약이므로, 원칙적으로 보험계약자·피보험자는 재보험사에 대해 직접 보험금을 청구할 권리가 없다. 원수보험사가 지급불능에 빠지더라도 계약자는 재보험사에 직접 청구할 수 없는 것이 원칙이며, 계약자 보호는 예금자보호제도 등 별도 제도가 담당한다. 재보험 출재 사실이 계약자의 보장 내용·청구 절차를 변경하지 않는다.', '재보험', array['보험계약자','직접청구권','재보험관계','원수보험사','예금자보호'], 'cycle3_mined', 'cycle3_mined', '위키백과 재보험 (ko.wikipedia.org) / 상법 보험편 (국가법령정보센터)', 'ai_draft', 'medium', 'admin'),
  ('term', '공동인수(Co-insurance, 공동보험)와 재보험의 구분', '공동인수(공동보험)는 하나의 위험을 다수의 원수보험사가 비율을 나누어 직접 인수하고 각자 그 비율만큼 계약자에게 직접 책임지는 방식으로, 계약자와 각 보험사 사이에 직접 관계가 성립한다. 반면 재보험은 한 원수보험사가 인수한 위험을 재보험사에 다시 전가하는 별도 계약이어서 계약자와 재보험사 사이에 직접 관계가 없다. 거대물건 인수 시 두 방법이 함께 쓰이기도 한다.', '재보험', array['공동인수','공동보험','Co-insurance','재보험구분','거대물건'], 'cycle3_mined', 'cycle3_mined', '위키백과 재보험 (ko.wikipedia.org) / 보험연구원 재보험 연구보고서 nre2019-1212 (kiri.or.kr)', 'ai_draft', 'medium', 'admin'),
  ('term', '재보험료(출재보험료)와 수재보험료의 흐름', '재보험 거래에서 출재사가 위험을 넘기는 대가로 수재사에게 지급하는 보험료를 출재보험료(재보험료)라 하고, 수재사 입장에서 이를 받는 것을 수재보험료라 한다. 비례재보험에서는 원보험료를 출재비율대로 나누고 출재수수료를 차감해 정산하며, 비비례재보험에서는 예측 손해를 기초로 산출한 정액·정률의 재보험료를 지급한다. 같은 돈이 출재사 관점에서는 출재보험료, 수재사 관점에서는 수재보험료가 된다.', '재보험', array['재보험료','출재보험료','수재보험료','비례재보험','비비례재보험'], 'cycle3_mined', 'cycle3_mined', '보험연구원 재보험 연구보고서 nre2019-1212 (kiri.or.kr) / 코리안리재보험 사업영역 (encykorea.aks.ac.kr)', 'ai_draft', 'medium', 'admin'),
  ('term', '위험집중(Accumulation)과 재보험 관리', '동일 지역·동일 원인(예: 한 도시의 지진, 한 빌딩 내 다수 계약)에서 하나의 사건으로 다수 계약의 손해가 동시에 발생해 손해가 집적되는 현상으로, 거대손해의 핵심 원인이다. 보험사는 위험집중을 한도 관리(누적한도)와 누적초과손해액재보험(Cat XL)·대재해채권 등으로 통제한다. 포트폴리오 단위로 집적 위험을 측정·관리하는 것이 지급여력 보호의 핵심이다.', '재보험', array['위험집중','Accumulation','누적한도','CatXL','거대손해'], 'cycle3_mined', 'cycle3_mined', '보험연구원 재보험 연구보고서 nre2019-1212 (kiri.or.kr) / 보험연구원 연구보고서 RE0002 대재해채권 (kiri.or.kr)', 'ai_draft', 'medium', 'admin'),
  ('term', '재보험의 거대위험 방어 기능(Catastrophe Protection)', '태풍·지진·홍수 등 한 사건으로 거액의 손해가 동시다발하는 거대재해에 대해, 보험사 자기보유로는 감당하기 어려운 손해를 재보험(특히 누적초과손해액재보험·대재해채권)을 통해 분산·전가하는 기능이다. 거대위험 방어는 보험사의 지급불능을 예방하고 계약자 보호에 직결되며, 재보험 인수능력을 넘는 부분은 자본시장(Cat Bond)으로 추가 전가하기도 한다.', '재보험', array['거대위험방어','CatastropheProtection','거대재해','CatXL','대재해채권'], 'cycle3_mined', 'cycle3_mined', '보험연구원 KiRi Weekly 대재해채권 (kiri.or.kr) / 보험연구원 연구보고서 RE0002 (kiri.or.kr)', 'ai_draft', 'medium', 'admin'),
  ('term', '비례재보험과 비비례재보험의 선택 기준', '비례재보험은 보험료·책임·손해를 비율로 나눠 인수능력 확충과 신생·소규모 사의 위험분산에 적합하고, 비비례재보험은 일정 금액·손해율을 초과하는 부분만 방어하여 거대·이상 손해 통제에 적합하다. 안정적·예측 가능한 위험분산이 목적이면 비례재보험을, 거대손해·실적 변동 방어가 목적이면 비비례재보험을 선택하는 것이 일반적이며, 실무에서는 두 방식을 결합해 운용한다.', '재보험', array['비례재보험','비비례재보험','재보험선택','인수능력','거대손해방어'], 'cycle3_mined', 'cycle3_mined', '보험연구원 재보험 연구보고서 nre2019-1212 (kiri.or.kr) / KiRi Weekly 2012.6.18 위험의 보유와 재보험 (kiri.or.kr)', 'ai_draft', 'medium', 'admin'),
  ('term', '재보험 자유화(1997년 재보험 시장 개방)', '국내 재보험 물량을 코리안리에 우선 출재하도록 한 국내우선출재제도가 1993~1997년에 걸쳐 폐지되고, 1997년 재보험 시장이 자유화되면서 해외 재보험사가 국내 시장에 진입하였다. 이로써 출재사는 국내·외 다수 재보험사 중 출재처를 자유롭게 선택할 수 있게 되었고, 코리안리의 시장점유율이 점차 낮아졌다. 재보험 거래의 경쟁·국제화가 진전된 계기다.', '재보험', array['재보험자유화','시장개방','국내우선출재폐지','해외재보험사','코리안리'], 'cycle3_mined', 'cycle3_mined', '코리안리재보험 (ko.wikipedia.org / encykorea.aks.ac.kr E0015175) / 한국공제보험신문 재보험사 탐방① (kongje.or.kr)', 'ai_draft', 'medium', 'admin'),
  ('term', '재보험 출재처(수재사) 선정·신용도 관리', '출재사는 출재한 위험을 실제로 회수할 수 있어야 하므로, 출재처(수재사)의 재무건전성·신용등급·지급능력을 평가하여 선정·관리해야 한다. 수재사가 지급불능에 빠지면 출재사는 보험금을 회수하지 못한 채 계약자에게 지급책임을 그대로 지게 되는 신용위험(재보험 회수위험)이 발생한다. 보험업감독규정 재보험관리기준은 이러한 출재처 관리·분산을 요구한다.', '재보험', array['출재처선정','수재사신용도','재보험회수위험','신용위험','재보험관리기준'], 'cycle3_mined', 'cycle3_mined', '보험업감독규정 및 시행세칙 재보험관리기준 (국가법령정보센터 law.go.kr) / 보험연구원 재보험 연구보고서 nre2019-1212 (kiri.or.kr)', 'ai_draft', 'medium', 'admin'),
  ('term', '재보험과 지급여력(K-ICS)·자본 경감 효과', '보험사가 위험을 출재하면 보유위험이 줄어들어 요구자본이 감소하고 지급여력비율(K-ICS)이 개선되는 효과가 있다. 이 때문에 재보험은 단순 위험분산을 넘어 자본관리(자본 경감) 수단으로 활용되며, 공동재보험은 금리·해약위험까지 이전해 K-ICS 부담을 완화하기 위해 도입되었다. 다만 위험전가 효과가 없는 재보험은 자본 경감 효과를 인정받지 못한다.', '재보험', array['지급여력','KICS','요구자본','자본경감','공동재보험'], 'cycle3_mined', 'cycle3_mined', '금융위원회 보도자료 공동재보험 도입방안 2020.1. (fsc.go.kr / korea.kr) / 보험업감독규정 재보험관리기준 (law.go.kr)', 'ai_draft', 'medium', 'admin'),
  ('term', '기왕증 감액(기왕장해 공제)', '상해보험에서 사고 전부터 존재하던 질병·신체장해(기왕증)가 손해 확대에 영향을 준 경우, 그 기여도만큼을 공제하고 보험금을 산정하는 실무를 말한다. 약관에 ''기왕장해·기왕증 공제'' 조항이 있으면 의학적 기여도(%)를 평가해 후유장해보험금에서 차감한다. 대법원도 사고와 무관한 기존 장해 부분은 보험자가 책임지지 않는다는 취지로 기여도 공제를 인정해 왔다.', '손해사정보험금', array['기왕증','기왕장해','기여도 공제','후유장해보험금','손해사정'], 'cycle3_mined', 'cycle3_mined', '질병·상해보험 표준약관(후유장해 지급률·기왕장해 공제 조항), 대법원 기여도 공제 판례', 'ai_draft', 'high', 'admin'),
  ('term', 'AMA 장해평가(맥브라이드·국가배상법 도표)', '후유장해 정도를 수치화하는 평가기준으로, 보험약관은 자체 ''장해분류표''를 쓰지만 손해배상·소송에서는 맥브라이드식이나 AMA Guides, 국가배상법 시행령 별표가 함께 거론된다. 평가방식에 따라 노동능력상실률·장해지급률이 달라져 보험금 산정에 직접 영향을 준다. 손해사정 시 어떤 기준을 적용했는지가 분쟁의 핵심이 된다.', '손해사정보험금', array['AMA장해평가','맥브라이드','노동능력상실률','장해지급률','후유장해'], 'cycle3_mined', 'cycle3_mined', '질병·상해보험 표준약관 장해분류표, 국가배상법 시행령 별표2 신체장해등급', 'ai_draft', 'medium', 'admin'),
  ('term', '손해방지의무(보험계약자·피보험자)', '손해보험에서 보험사고 발생 시 또는 발생 위험이 있을 때 계약자·피보험자가 손해의 발생·확대를 방지·경감하기 위해 노력해야 하는 의무다(상법 제680조). 이 의무 이행에 필요·유익했던 비용은 보험금액을 초과하더라도 보험자가 부담한다. 의무를 게을리해 늘어난 손해는 보상에서 제외될 수 있다.', '손해사정보험금', array['손해방지의무','손해방지비용','상법 제680조','손해경감','손해보험'], 'cycle3_mined', 'cycle3_mined', '상법 제680조(손해방지의무), 손해보험 표준약관 손해방지비용 조항', 'ai_draft', 'high', 'admin'),
  ('term', '잔존물 제거비용', '화재 등 손해보험 사고에서 피해 재산의 잔존물을 해체·청소·상차·하차하는 데 드는 비용을 말한다. 약관상 보험가입금액의 일정 비율(통상 10%) 한도로 보상되며, 손해액과 합산해 보험가입금액을 초과해도 별도 한도로 지급되는 경우가 많다. 오염물질 제거·하수관 청소 비용은 통상 제외된다.', '손해사정보험금', array['잔존물 제거비용','화재보험','보상한도','손해사정','비용손해'], 'cycle3_mined', 'cycle3_mined', '화재보험 표준약관(잔존물 제거비용 조항), 보험업감독업무시행세칙 표준약관', 'ai_draft', 'medium', 'admin'),
  ('term', '대위권 포기(구상권 포기 특약)', '보험자가 보험금 지급 후 취득하는 제3자에 대한 구상권(청구권대위)을 미리 포기하기로 약정하는 것을 말한다. 임대차·도급 등 거래관계에서 거래상대방을 보호하기 위해 보험약관이나 특약으로 설정되며, ''Waiver of Subrogation''으로 불린다. 대위권을 포기하면 보험자는 사고 책임자에게 구상할 수 없다.', '손해사정보험금', array['대위권 포기','구상권 포기','청구권대위','Waiver of Subrogation','손해보험'], 'cycle3_mined', 'cycle3_mined', '상법 제682조(제3자에 대한 보험대위), 영업배상책임보험 약관 대위권포기 특약', 'ai_draft', 'medium', 'admin'),
  ('term', '손해사정서', '손해사정사가 보험사고의 원인·손해액·보험금 지급 여부 및 금액 등을 조사·산정해 작성하는 공식 문서다. 보험금 지급의 근거가 되며, 손해사정사는 손해사정서 작성 후 지체 없이 보험회사·보험계약자·피보험자·보험금청구권자에게 교부하고 그 중요한 내용을 알려야 한다. 보험계약자 등은 손해사정서 열람·사본 교부를 요청할 수 있고 이의가 있으면 의견을 제출할 수 있다.', '손해사정보험금', array['손해사정서','손해사정사','보험금 산정','보험업법','보상실무'], 'cycle3_mined', 'cycle3_mined', '보험업법 시행령 제99조(손해사정서 작성·교부 의무), 보험업법 제185조·제188조', 'ai_draft', 'high', 'admin'),
  ('term', '독립손해사정사 선임권', '보험계약자·피보험자가 보험회사가 선임한 손해사정사 대신 자신이 직접 손해사정사를 선임해 손해사정을 받을 수 있는 권리다. 보험회사는 금융위원회가 정하는 선임 동의기준을 충족하면 이에 동의하여야 하며, 일정 요건 충족 시 선임비용을 보험회사가 부담한다. 보험회사 자기손해사정의 공정성 문제를 보완하기 위한 제도다.', '손해사정보험금', array['독립손해사정사','손해사정사 선임권','피보험자 선임권','자기손해사정','보험업법'], 'cycle3_mined', 'cycle3_mined', '보험업법 제185조(손해사정)·보험업감독규정(손해사정사 선임 및 비용부담)', 'ai_draft', 'high', 'admin'),
  ('term', '손해사정사 종별(재물·차량·신체·종합)', '손해사정사는 취급 분야에 따라 재물손해사정사, 차량손해사정사, 신체손해사정사, 종합손해사정사로 구분된다. 각 종별은 금융감독원이 시행하는 시험과 실무수습을 거쳐 등록하며, 취급할 수 있는 손해 영역이 다르다. 보험금 청구 시 사고 유형에 맞는 종별의 손해사정사가 산정을 담당한다.', '손해사정보험금', array['손해사정사 종별','재물손해사정사','신체손해사정사','차량손해사정사','자격구분'], 'cycle3_mined', 'cycle3_mined', '보험업법 시행규칙 제52조(손해사정사의 구분), 금융감독원 손해사정사 자격시험 안내', 'ai_draft', 'medium', 'admin'),
  ('term', '보험금 청구권 양도', '보험사고 발생 후 구체적으로 발생한 보험금 청구권을 제3자에게 양도하는 것을 말한다. 지명채권 양도의 방법에 따라 보험자에 대한 통지 또는 보험자의 승낙이 있어야 대항력이 생긴다. 병원 등에 청구권을 양도해 직접 정산하는 실무에서 활용되며, 약관상 양도 제한 조항이 있을 수 있다.', '손해사정보험금', array['보험금청구권 양도','채권양도','지명채권','대항요건','보험금 청구'], 'cycle3_mined', 'cycle3_mined', '민법 제449조~제451조(채권양도), 보험 표준약관 보험금청구권 관련 조항', 'ai_draft', 'medium', 'admin'),
  ('term', '질권 설정(보험계약상 권리의 입질)', '보험계약자가 보험금청구권이나 해약환급금청구권을 채권자에게 담보로 제공하기 위해 질권을 설정하는 것을 말한다. 보험자에 대한 통지·승낙으로 대항요건을 갖추며, 약관대출과 달리 제3채권자가 권리를 행사한다. 사망보험금에 질권을 설정하려면 피보험자 동의 등 요건을 충족해야 한다.', '손해사정보험금', array['질권 설정','보험금청구권 질권','담보','약관대출','보험계약상 권리'], 'cycle3_mined', 'cycle3_mined', '민법 제345조 이하(권리질권), 생명보험 표준약관 질권설정 관련 조항', 'ai_draft', 'medium', 'admin'),
  ('term', '보험위부(전손에 준하는 처리)', '해상보험 등에서 선박·적하의 전부 멸실에 준하는 상황(추정전손)일 때 피보험자가 보험목적물에 대한 일체의 권리를 보험자에게 넘기고 전손에 해당하는 보험금 전액을 청구할 수 있는 제도다(상법 제710조 이하). 위부의 원인이 있으면 피보험자는 위부를 통지해야 한다. 일반 손해보험에는 잘 쓰이지 않으나 손해사정의 기본 개념이다.', '손해사정보험금', array['보험위부','추정전손','해상보험','상법 제710조','손해사정'], 'cycle3_mined', 'cycle3_mined', '상법 제710조~제718조(보험위부)', 'ai_draft', 'high', 'admin'),
  ('term', '공동불법행위와 보험자 간 구상', '여러 가해자의 공동불법행위로 손해가 발생한 경우, 한 보험자가 피해자에게 보험금을 지급한 뒤 다른 가해자(또는 그 보험자)에게 부담부분만큼 구상하는 법률관계를 말한다. 각 가해자의 과실비율에 따라 부담부분이 정해지며, 보험자대위(상법 제682조)와 결합해 구상권을 행사한다. 다수 보험자 사이 정산 실무의 핵심이다.', '손해사정보험금', array['공동불법행위','구상권','부담부분','보험자대위','과실비율'], 'cycle3_mined', 'cycle3_mined', '민법 제760조(공동불법행위)·제425조(구상권), 상법 제682조', 'ai_draft', 'medium', 'admin'),
  ('term', '중복보험 비례분담(연대비례주의)', '동일 피보험이익에 수개의 손해보험이 중복 가입돼 보험금액 합계가 보험가액을 초과한 경우, 각 보험자가 보험금액 비율에 따라 손해를 분담하고 피보험자에게는 연대책임을 지는 방식이다(상법 제672조). 피보험자는 어느 보험자에게든 전액 청구할 수 있고, 지급한 보험자는 다른 보험자에게 분담을 구상한다. 실손 중복가입 정산의 법리적 근거다.', '손해사정보험금', array['중복보험 비례분담','연대비례주의','상법 제672조','독립책임액','손해사정'], 'cycle3_mined', 'cycle3_mined', '상법 제672조(중복보험)', 'ai_draft', 'high', 'admin'),
  ('term', '통원·입원 분류 기준(6시간 이상 체류)', '실손 등 보험금 산정에서 입원과 통원을 구분하는 기준으로, 의료법령은 의료기관 내 6시간 이상 체류하며 의사의 지속적 관찰 하에 치료받는 것을 입원으로 본다. 다만 최근 판례는 6시간 체류만으로 입원이 인정되는 것은 아니며 증상·치료내용·관리 정도를 종합해 판단해야 한다고 보아, 단순 체류시간은 절대적 기준이 아니다. 응급실 장시간 대기·낮병동 처치의 입원 인정 여부가 자주 다투어진다.', '손해사정보험금', array['입원 인정 기준','통원 입원 구분','6시간 체류','낮병동','보험금 산정'], 'cycle3_mined', 'cycle3_mined', '의료법 시행규칙(입원의 정의), 질병·상해보험 표준약관, 대법원·하급심 입원 판단 판례', 'ai_draft', 'medium', 'admin'),
  ('term', '제3의료기관 감정(의료감정 합의)', '보험금 분쟁 시 주치의 진단과 보험사 의료자문 결과가 다를 때, 계약자와 보험사가 합의해 종합병원 등 제3의 의료기관에서 다시 감정을 받아 그 결과로 분쟁을 해소하는 절차다. 약관에 절차와 비용 부담 방법이 규정돼 있으며, 객관적 판정을 위한 장치다. 합의 감정 결과는 보험금 산정의 기준이 된다.', '손해사정보험금', array['제3의료기관','의료감정','장해 분쟁','주치의 소견','손해사정'], 'cycle3_mined', 'cycle3_mined', '질병·상해보험 표준약관(보험금 지급 관련 분쟁 해결 조항)', 'ai_draft', 'medium', 'admin'),
  ('term', '보험금 지급심사 지연과 기초조사', '보험회사가 보험금 청구를 받으면 약관상 지급기일(통상 3영업일, 조사 필요 시 연장) 내 지급해야 하며, 추가 조사가 필요하면 그 사유와 예상 지급일을 통지해야 한다. 정당한 사유 없이 심사를 지연하면 지연이자 부담과 제재 대상이 된다. 보험사기 의심 등 조사 필요성과 신속지급 의무의 균형이 쟁점이다.', '손해사정보험금', array['지급심사 지연','지급기일','기초조사','지연이자','보험금 지급'], 'cycle3_mined', 'cycle3_mined', '보험 표준약관(보험금 지급절차·지급기일 조항), 보험업감독규정', 'ai_draft', 'high', 'admin'),
  ('term', '우연성·외래성·급격성(상해 3요건)', '상해보험에서 보험금 지급 대상인 ''상해''로 인정되려면 사고가 우연하고(예견 불가), 외래적이며(신체 외부 원인), 급격하게(돌발적) 발생해야 한다는 세 가지 요건을 말한다. 질병에 의한 신체 내부 원인이나 예견 가능한 결과는 상해로 보지 않는다. 보험금 부지급 분쟁에서 이 3요건 충족 여부가 핵심 쟁점이 된다.', '손해사정보험금', array['상해 3요건','우연성','외래성','급격성','상해보험'], 'cycle3_mined', 'cycle3_mined', '질병·상해보험 표준약관(상해의 정의), 대법원 상해 인정 판례', 'ai_draft', 'high', 'admin'),
  ('term', '사망의 추정·인정(실종선고)', '피보험자의 생사가 분명하지 않을 때 사망보험금 지급 여부를 결정하기 위해 실종선고(민법)나 인정사망(가족관계등록법) 제도를 적용하는 문제다. 항공·해난 등 위난실종은 1년, 보통실종은 5년이 지나야 실종선고로 사망이 의제된다. 약관은 관공서의 사망 통보·인정사망을 사망보험금 지급 근거로 삼기도 한다.', '손해사정보험금', array['실종선고','인정사망','사망보험금','민법 실종','사망 추정'], 'cycle3_mined', 'cycle3_mined', '민법 제27조~제29조(실종선고), 가족관계등록법(인정사망)', 'ai_draft', 'medium', 'admin'),
  ('term', '동시사망 추정과 보험수익자', '피보험자와 보험수익자가 동일 사고로 사망해 사망의 선후를 알 수 없는 경우, 민법상 동시에 사망한 것으로 추정한다(민법 제30조). 이 추정에 따라 사망보험금이 누구에게 귀속되는지(상속인 범위)가 달라진다. 보험금 귀속과 상속 분쟁에서 동시사망 추정의 적용 여부가 핵심이 된다.', '손해사정보험금', array['동시사망 추정','민법 제30조','보험수익자','사망보험금','상속'], 'cycle3_mined', 'cycle3_mined', '민법 제30조(동시사망의 추정), 생명보험 표준약관 수익자 관련 조항', 'ai_draft', 'high', 'admin'),
  ('term', '보험수익자 미지정 시 보험금 귀속', '사망보험금의 수익자를 지정하지 않은 경우 약관과 상법에 따라 피보험자의 상속인이 보험수익자가 되며, 상속인은 보험금을 고유재산으로 취득한다는 것이 판례다. 따라서 상속포기를 해도 사망보험금은 받을 수 있고, 원칙적으로 상속채무와 분리된다. 수익자 지정 여부가 보험금 귀속·상속관계에 큰 영향을 준다.', '손해사정보험금', array['수익자 미지정','상속인','고유재산','상속포기','사망보험금'], 'cycle3_mined', 'cycle3_mined', '상법 제733조(보험수익자의 지정·변경), 대법원 사망보험금 고유재산 판례', 'ai_draft', 'high', 'admin'),
  ('term', '보험사고의 입증책임 분배', '보험금 청구에서 보험사고의 발생 사실은 청구하는 측(계약자·수익자)이 입증하고, 면책사유의 존재는 보험자가 입증한다는 입증책임 분배 원칙을 말한다. 자살·고의·음주 등 면책은 보험자가 증명해야 보험금을 거절할 수 있다. 입증책임이 누구에게 있는지가 분쟁 승패를 가르는 핵심이다.', '손해사정보험금', array['입증책임','면책사유 입증','보험사고 입증','고의 면책','보험금 분쟁'], 'cycle3_mined', 'cycle3_mined', '상법 보험편·민사소송법상 입증책임 분배, 대법원 면책사유 입증 판례', 'ai_draft', 'high', 'admin'),
  ('term', '심신상실 중 자해(자살면책 예외)', '고의 자해는 면책이지만, 피보험자가 심신상실 등으로 자유로운 의사결정을 할 수 없는 상태에서 자신을 해친 경우에는 사망보험금이 지급될 수 있다는 약관·판례상 예외다. 우울증 등 정신질환으로 인한 자유의지 상실 여부가 핵심 쟁점이 된다. 보험자는 고의성을, 청구자는 심신상실을 둘러싸고 다툰다.', '손해사정보험금', array['심신상실','자살 면책 예외','자유로운 의사결정','우울증','사망보험금'], 'cycle3_mined', 'cycle3_mined', '생명보험 표준약관(자살 면책 및 예외 조항), 대법원 심신상실 자살 판례', 'ai_draft', 'high', 'admin'),
  ('term', '음주·무면허운전 면책약관의 효력', '상해보험에서 음주·무면허운전 중 사고를 면책하는 약관 조항이 어디까지 유효한지에 관한 문제다. 판례는 손해 발생 원인에 대한 책임을 경감하는 면책(과실로 평가되는 사고까지 일률 면책)은 상법 제663조(보험계약자 등 불이익변경금지)에 반해 무효일 수 있다고 본다. 면책범위와 인과관계 요구 여부가 보험금 산정의 쟁점이 된다.', '손해사정보험금', array['음주운전 면책','무면허운전 면책','불이익변경금지','상법 제663조','상해보험'], 'cycle3_mined', 'cycle3_mined', '상법 제663조(보험계약자 등의 불이익변경금지), 대법원 음주·무면허 면책 판례(96다4909 등)', 'ai_draft', 'medium', 'admin'),
  ('term', '보험계약자 등의 고의·중과실 면책', '보험계약자, 피보험자 또는 보험수익자의 고의 또는 중대한 과실로 생긴 보험사고는 보험자가 보상하지 않는다는 면책 원칙이다(상법 제659조). 다만 사망을 보험사고로 한 보험계약에서는 중과실 사고를 면책으로 하지 못한다(상법 제732조의2). 고의·중과실의 인정 범위가 보험금 부지급 분쟁의 핵심이다.', '손해사정보험금', array['고의 면책','중과실 면책','상법 제659조','상법 제732조의2','인보험'], 'cycle3_mined', 'cycle3_mined', '상법 제659조(보험자의 면책사유)·제732조의2(중과실로 인한 보험사고 등)', 'ai_draft', 'high', 'admin'),
  ('term', '보험료 부지급과 계약 해제·실효', '제1회 보험료를 약정 기간 내 내지 않으면 계약이 해제된 것으로 보고(상법 제650조 제1항), 계속보험료를 연체하면 최고 후 계약을 해지할 수 있다. 실효 전 발생한 사고의 보험금 지급 여부, 부활을 통한 보장 회복 가능성이 쟁점이 된다. 미납과 보장 단절의 시점 판단이 보험금 산정에 직접 영향을 준다.', '손해사정보험금', array['보험료 부지급','계약 해제','상법 제650조','실효','보험금 지급'], 'cycle3_mined', 'cycle3_mined', '상법 제650조(보험료의 지급과 지체의 효과)', 'ai_draft', 'high', 'admin'),
  ('term', '타인을 위한 보험계약', '보험계약자가 자기가 아닌 타인(피보험자 또는 수익자)의 이익을 위해 체결하는 보험계약을 말한다(상법 제639조). 손해보험에서는 타인의 위임 없이도 체결할 수 있으나 그 사실을 보험자에게 고지해야 하고, 보험금청구권은 타인에게 귀속된다. 계약자와 보험금 수령자가 다를 때 권리관계 정리의 기초가 된다.', '손해사정보험금', array['타인을 위한 보험','상법 제639조','피보험자','보험금청구권 귀속','보험계약'], 'cycle3_mined', 'cycle3_mined', '상법 제639조(타인을 위한 보험)', 'ai_draft', 'high', 'admin'),
  ('term', '보험계약자의 임의해지권과 환급', '보험사고 발생 전에는 보험계약자가 언제든지 계약의 전부 또는 일부를 해지할 수 있고, 미경과 보험료·해약환급금을 돌려받는다(상법 제649조). 타인을 위한 보험은 그 타인의 동의나 증권 소지가 필요할 수 있다. 해지 시점에 따른 환급금 산정이 실무 분쟁의 대상이 된다.', '손해사정보험금', array['임의해지권','상법 제649조','미경과보험료','해약환급금','계약 해지'], 'cycle3_mined', 'cycle3_mined', '상법 제649조(사고발생 전의 임의해지)', 'ai_draft', 'high', 'admin'),
  ('term', '고지의무 위반과 인과관계 부존재(보험금 지급)', '고지의무를 위반했더라도 그 위반 사실과 발생한 보험사고 사이에 인과관계가 없으면 보험자는 해당 보험금을 지급해야 한다는 원칙이다(상법 제655조 단서). 즉 부실고지한 질병과 무관한 사고로 보험금을 청구하면 지급될 수 있다. 인과관계 존부가 보험금 지급·삭감의 핵심 판단 기준이 된다.', '손해사정보험금', array['고지의무 위반','인과관계 부존재','상법 제655조','보험금 지급','해지'], 'cycle3_mined', 'cycle3_mined', '상법 제655조(계약해지와 보험금청구권), 대법원 인과관계 판례', 'ai_draft', 'high', 'admin'),
  ('term', '청구권대위와 피보험자 권리 우선(보험자대위 제한)', '보험자가 일부보험금만 지급한 경우, 청구권대위로 제3자에게 구상하더라도 피보험자가 가해자로부터 받지 못한 손해(미보상 부분)를 우선 회수할 권리가 보장된다. 즉 보험자는 피보험자의 권리를 침해하지 않는 범위에서만 대위·구상할 수 있다(상법 제682조 단서 취지). 일부보험·과실상계 사안에서 정산 순위가 쟁점이 된다.', '손해사정보험금', array['청구권대위','피보험자 우선','보험자대위 제한','상법 제682조','일부보험'], 'cycle3_mined', 'cycle3_mined', '상법 제682조(제3자에 대한 보험대위), 대법원 피보험자 우선 회수 판례', 'ai_draft', 'high', 'admin'),
  ('term', '보험사기 적발 시 보험금 환수·계약 무효', '고의로 사고를 가장·과장해 보험금을 편취한 경우 보험금 지급이 거절되고 이미 지급된 보험금은 부당이득으로 환수되며, 보험사기로 체결된 계약은 무효·취소될 수 있다. 형사처벌(보험사기방지 특별법)과 별도로 민사상 환수가 이루어진다. 사기 입증과 정상 청구의 구분이 손해사정의 쟁점이 된다.', '손해사정보험금', array['보험사기 환수','부당이득','계약 무효','보험사기방지 특별법','보험금 부지급'], 'cycle3_mined', 'cycle3_mined', '보험사기방지 특별법, 민법 부당이득 규정, 보험 표준약관 사기 관련 조항', 'ai_draft', 'high', 'admin'),
  ('term', '보험금 분할지급·연금형 지급', '사망·후유장해 보험금 등을 일시금이 아니라 일정 기간 분할(연금형)로 지급하기로 한 지급방식을 말한다. 약관에 분할지급 이율과 잔여 미지급분의 일시 정산 방법이 규정된다. 미성년 수익자 보호, 세제 등을 고려해 선택되며, 지급방식 변경 가능 여부가 실무 쟁점이 된다.', '손해사정보험금', array['분할지급','연금형 지급','보험금 지급방식','지급이율','수익자 보호'], 'cycle3_mined', 'cycle3_mined', '생명보험 표준약관(보험금 분할지급 조항)', 'ai_draft', 'medium', 'admin'),
  ('term', '가지급보험금(보험금 가지급제도)', '보험금 지급사유는 인정되나 정확한 금액 산정에 시간이 걸릴 때, 보험자가 예상 지급액의 일부를 미리 지급하는 제도다. 본 보험금 확정 후 정산하며, 계약자의 긴급한 자금 수요를 덜어준다. 가지급 후 부지급으로 확정되면 반환 문제가 발생한다.', '손해사정보험금', array['가지급보험금','가지급제도','선지급','보험금 산정','지급절차'], 'cycle3_mined', 'cycle3_mined', '보험 표준약관(가지급금 관련 조항), 보험업감독규정', 'ai_draft', 'medium', 'admin'),
  ('term', '보험금 지연이자율(보험계약대출이율 적용)', '보험자가 약관상 지급기일을 넘겨 보험금을 늦게 지급할 때 가산되는 이자로, 통상 보험계약대출이율 등 약관에 정한 이율을 적용한다. 조사·소송 등 정당한 사유로 지연된 기간은 이율이 달라지거나 제외될 수 있다. 지연이자 기산점과 적용이율이 분쟁의 대상이 된다.', '손해사정보험금', array['지연이자','보험계약대출이율','지급기일','보험금 지급','손해사정'], 'cycle3_mined', 'cycle3_mined', '보험 표준약관(보험금 지급기일·지연이자 조항)', 'ai_draft', 'medium', 'admin'),
  ('term', '자동차손해배상보장사업(정부보장사업)', '뺑소니·무보험차 사고 등으로 자동차보험에서 보상받지 못하는 피해자를 구제하기 위해 정부가 운영하는 보장사업이다(자배법 제30조). 피해자는 정부보장사업을 통해 대인배상 I 수준의 보상을 받을 수 있으며, 정부는 가해자에게 구상한다. 피해자 최후 구제 수단으로서 손해사정 실무의 한 축이다.', '손해사정보험금', array['정부보장사업','뺑소니','무보험차','자배법 제30조','피해자 구제'], 'cycle3_mined', 'cycle3_mined', '자동차손해배상보장법 제30조(자동차손해배상 보장사업)', 'ai_draft', 'medium', 'admin'),
  ('term', '과실상계와 손익상계', '손해배상·보험금 산정에서 피해자의 과실비율만큼 배상액을 줄이는 것이 과실상계, 피해자가 같은 사고로 얻은 이익(중복 수령 보상 등)을 공제하는 것이 손익상계다. 두 상계의 적용 순서와 범위에 따라 최종 보험금·배상액이 달라진다. 자동차·배상책임 사고 정산에서 핵심 계산 원리다.', '손해사정보험금', array['과실상계','손익상계','배상액 산정','공제','손해사정'], 'cycle3_mined', 'cycle3_mined', '민법 제396조(과실상계), 대법원 과실상계·손익상계 순서 판례', 'ai_draft', 'medium', 'admin'),
  ('term', '휴업손해·상실수익액 산정', '신체사고로 일하지 못한 기간의 소득 감소를 보상하는 것이 휴업손해이고, 후유장해로 장래 소득이 줄어드는 손해를 현재가치로 환산한 것이 상실수익액(일실수입)이다. 소득·노동능력상실률·가동연한·호프만(라이프니츠) 계수를 적용해 산정한다. 인보험·배상책임 보험금 산정의 핵심 계산 항목이다.', '손해사정보험금', array['휴업손해','상실수익액','일실수입','노동능력상실률','호프만계수'], 'cycle3_mined', 'cycle3_mined', '대법원 손해배상 산정 기준, 자동차보험 표준약관(대인 지급기준)', 'ai_draft', 'medium', 'admin'),
  ('term', '위자료 산정기준(사망·후유장해)', '사고로 인한 정신적 손해를 금전으로 보상하는 위자료의 산정기준으로, 자동차보험 약관은 사망·후유장해 정도별 정액 기준표를 두고 법원은 별도 기준(사망 위자료 기준금액 등)을 적용한다. 약관 기준과 소송 기준에 차이가 있어 합의·소송 선택에 영향을 준다. 보험금 산정·합의 실무의 주요 항목이다.', '손해사정보험금', array['위자료','사망 위자료','후유장해 위자료','약관 기준','손해배상'], 'cycle3_mined', 'cycle3_mined', '자동차보험 표준약관(대인배상 위자료 지급기준), 법원 위자료 산정기준', 'ai_draft', 'medium', 'admin'),
  ('term', '향후치료비·개호비 산정', '사고 이후 장래에 필요한 치료비(향후치료비)와 중증 후유장해로 타인의 간병이 필요한 비용(개호비)을 손해배상·보험금 항목으로 산정하는 것을 말한다. 의학적 소견에 따른 치료 필요성·기간, 개호 필요 정도(전부·일부)와 개호인 단가를 기준으로 한다. 중상해 사건 보험금 산정의 핵심 쟁점이다.', '손해사정보험금', array['향후치료비','개호비','간병비','중상해','손해사정'], 'cycle3_mined', 'cycle3_mined', '대법원 향후치료비·개호비 산정 판례, 자동차보험 표준약관 지급기준', 'ai_draft', 'medium', 'admin'),
  ('term', '비용손해(손해방지·잔존물보전·구조비용)', '손해보험에서 손해 자체 외에 손해방지비용, 잔존물 보전·정리비용, 구조비용 등 사고 처리를 위해 지출한 비용을 별도로 보상하는 손해 유형이다. 일부는 보험가입금액과 별도 한도로, 일부는 한도 내에서 보상된다. 손해액 산정 시 비용손해 항목의 구분이 필요하다.', '손해사정보험금', array['비용손해','손해방지비용','잔존물보전비용','구조비용','손해사정'], 'cycle3_mined', 'cycle3_mined', '상법 제680조, 손해보험 표준약관(비용손해 보상 조항)', 'ai_draft', 'medium', 'admin'),
  ('term', '전부보험·일부보험·초과보험의 보상관계', '보험금액이 보험가액과 같으면 전부보험(전액 보상), 작으면 일부보험(비례보상), 크면 초과보험(초과분 무효)으로 보상관계가 달라진다. 일부보험은 보험금액의 보험가액에 대한 비율로 보상하고(상법 제674조), 초과보험은 선의·악의에 따라 효력이 다르다(상법 제669조). 손해액 산정의 출발 구조다.', '손해사정보험금', array['전부보험','일부보험','초과보험','비례보상','상법 제674조'], 'cycle3_mined', 'cycle3_mined', '상법 제669조(초과보험)·제674조(일부보험)', 'ai_draft', 'high', 'admin'),
  ('term', '보험금 지급사유와 면책사유의 경합', '하나의 사고에 보험금 지급사유와 면책사유가 함께 관련된 경우, 어떤 원인이 손해에 기여했는지(주된 원인·근인주의)에 따라 지급 여부를 판단하는 문제다. 면책사유에 해당하는 부분과 보상되는 부분을 어떻게 나눌지가 쟁점이 된다. 다발 원인 사고 손해사정의 핵심 판단이다.', '손해사정보험금', array['지급사유','면책사유 경합','근인주의','원인 기여','보험금 산정'], 'cycle3_mined', 'cycle3_mined', '상법 보험편, 대법원 보험사고 인과·근인 판례', 'ai_draft', 'medium', 'admin'),
  ('term', '보험금청구권 소멸시효 중단·정지', '보험금청구권은 3년의 소멸시효에 걸리는데(상법 제662조), 청구·압류·승인 등으로 시효가 중단되거나 천재지변 등으로 정지될 수 있다. 보험자의 일부 지급이나 지급 약속은 채무 승인으로 시효를 중단시킨다. 시효 완성 여부와 중단 사유 존부가 보험금 청구 가능성을 좌우한다.', '손해사정보험금', array['소멸시효','상법 제662조','시효 중단','채무 승인','보험금청구권'], 'cycle3_mined', 'cycle3_mined', '상법 제662조(소멸시효), 민법 제168조 이하(시효의 중단)', 'ai_draft', 'high', 'admin'),
  ('term', '단체보험의 보험금 귀속', '회사 등이 종업원을 피보험자로 단체보험을 체결한 경우, 사망보험금이 회사(계약자)와 유족 중 누구에게 귀속되는지의 문제다. 규약에 따른 단체보험은 피보험자 개별 서면동의(상법 제731조)가 면제되나, 규약이 없으면 서면동의가 필요하고, 수익자 지정 내용에 따라 귀속이 달라진다. 단체보험 보험금 분쟁의 핵심 쟁점이다.', '손해사정보험금', array['단체보험','보험금 귀속','피보험자 동의','상법 제735조의3','유족'], 'cycle3_mined', 'cycle3_mined', '상법 제735조의3(단체보험)·제731조(타인의 생명보험)', 'ai_draft', 'high', 'admin'),
  ('term', '무해지환급형(무해지환급금형)', '보험기간 중 계약을 해지할 때 해지환급금이 없거나 표준형보다 적은 대신 보험료가 저렴하게 설계된 보장성보험 유형이다. 납입기간 중 해지 시 환급금이 없거나 거의 없으나, 납입완료 시점부터는 표준형과 동일한 환급금을 지급하는 구조가 일반적이다. 금융당국은 무·저해지 상품의 불완전판매를 막기 위해 2021년 보험업감독규정 등을 통해 납입 만기 후 환급률을 표준형 이내로 제한하고, 납입기간 중 해지환급금이 표준형의 50% 미만인 상품(예: 10% 환급형)의 판매를 중단시켰다(2021년 8월 시행).', '상품구조특약', array['무해지환급','해지환급금','보장성보험','보험료절감','불완전판매'], 'cycle3_mined', 'cycle3_mined', '금융위원회·금융감독원 무·저해지보험 상품구조 개선 및 보험업감독규정 개정(2021)', 'ai_draft', 'high', 'admin'),
  ('term', '저해지환급형(저해지환급금형)', '납입기간 중 해지환급금을 표준형보다 낮게 설계해 보험료를 낮춘 보장성보험 유형이다. 무해지형이 환급금을 거의 없애는 반면 저해지형은 일부를 남겨두는 점이 다르며, 납입 완료 후에는 표준형과 환급금이 같아지는 구조가 일반적이다. 금융당국 규제로 납입기간 중 해지환급금이 표준형의 50% 이상이 되도록 개정된 상품이 판매되고 있다. 저렴한 보험료가 장점이나 납입기간 중 중도해지 시 손실이 크다는 점을 반드시 설명해야 한다.', '상품구조특약', array['저해지환급','해지환급금','보험료절감','보장성보험','중도해지'], 'cycle3_mined', 'cycle3_mined', '금융위원회·금융감독원 무·저해지보험 상품구조 개선 및 보험업감독규정 개정(2021)', 'ai_draft', 'high', 'admin'),
  ('term', '기본계약과 선택계약 구조', '보험상품은 반드시 가입해야 하는 기본계약(주계약)과 보장을 추가로 선택할 수 있는 선택계약(특약)으로 구성된다. 기본계약만으로도 보험이 성립하지만 선택계약은 단독으로 가입할 수 없고 기본계약에 부가되어야 효력이 발생한다. 선택특약은 계약자가 보장 필요에 따라 가입·해지를 조절할 수 있어 맞춤형 보장 설계의 핵심이 된다.', '상품구조특약', array['기본계약','선택계약','주계약','특약구조','보장설계'], 'cycle3_mined', 'cycle3_mined', '생명보험협회 보험상품 공시 가이드라인 및 표준약관', 'ai_draft', 'high', 'admin'),
  ('term', '의무부가특약과 선택부가특약', '의무부가특약은 주계약에 반드시 따라붙어 별도로 뗄 수 없는 특약이고, 선택부가특약은 계약자가 필요에 따라 가입 여부를 정할 수 있는 특약이다. 의무특약은 상품 설계상 보장의 일부로 묶여 있어 해지하면 주계약 전체에 영향을 줄 수 있다. 가입 시 어떤 특약이 의무이고 선택인지 구분해 설명해야 추후 해지·변경 분쟁을 막을 수 있다.', '상품구조특약', array['의무부가특약','선택부가특약','특약구조','특약해지','보장설계'], 'cycle3_mined', 'cycle3_mined', '생명·손해보험협회 표준약관 및 보험상품 공시기준', 'ai_draft', 'high', 'admin'),
  ('term', '독립특약과 종속특약', '독립특약은 주계약과 별개로 독자적인 보험기간·보험료를 가져 주계약이 소멸해도 유지될 수 있는 특약이고, 종속특약은 주계약에 종속되어 주계약이 소멸하면 함께 소멸하는 특약이다. 갱신형 특약 중 일부는 주계약과 보험기간이 달라 독립적으로 갱신되며, 종속특약은 주계약 보험기간과 운명을 같이한다. 특약의 독립·종속 여부에 따라 해지·만기·갱신 처리가 달라진다.', '상품구조특약', array['독립특약','종속특약','특약구조','특약만기','주계약소멸'], 'cycle3_mined', 'cycle3_mined', '생명·손해보험협회 표준약관', 'ai_draft', 'medium', 'admin'),
  ('term', '제도성특약(세제·서비스 부가특약)', '제도성특약은 보장을 추가하는 것이 아니라 계약 관리·세제 혜택·서비스 제공을 목적으로 부가하는 특약으로, 보험료가 없거나 매우 낮은 것이 특징이다. 대표적으로 연금전환특약, 보험료자동대출납입특약, 장애인전용보험 전환특약 등이 있다. 보장특약과 달리 위험보장이 목적이 아니므로 계약자가 제도 활용을 위해 선택하는 성격이 강하다.', '상품구조특약', array['제도성특약','세제특약','연금전환특약','서비스특약','무료특약'], 'cycle3_mined', 'cycle3_mined', '생명보험협회 보험상품 공시 가이드라인 및 표준약관', 'ai_draft', 'medium', 'admin'),
  ('term', '보장성보험 특약 보험료 구성(위험보험료·부가보험료·저축보험료)', '보험료는 보험금 지급 재원인 위험보험료, 사업비에 해당하는 부가보험료, 만기·해지 시 돌려줄 재원인 저축보험료(적립보험료)로 구성된다. 순보험료는 위험보험료와 저축보험료의 합이며, 영업보험료는 여기에 부가보험료를 더한 실제 납입액이다. 보장성특약은 위험보험료 비중이 크고 저축성상품은 저축보험료 비중이 크다.', '상품구조특약', array['위험보험료','부가보험료','저축보험료','순보험료','영업보험료'], 'cycle3_mined', 'cycle3_mined', '보험업감독규정 및 생명보험협회 보험료 산출 공시기준', 'ai_draft', 'high', 'admin'),
  ('term', '평준보험료(平準保險料) 방식', '보험기간 동안 위험률이 증가해도 매달 같은 보험료를 내도록 전 기간 보험료를 평준화한 산출 방식이다. 가입 초기에는 실제 위험보험료보다 많이 내어 그 차액을 적립하고, 후반에는 적립금에서 부족분을 충당하는 구조다. 이 초과 적립분이 책임준비금과 해지환급금의 재원이 되며, 종신·정기보험 등 장기보험의 기본 산출방식이다.', '상품구조특약', array['평준보험료','자연보험료','책임준비금','적립금','보험료산출'], 'cycle3_mined', 'cycle3_mined', '보험업감독규정 및 생명보험협회 보험료 산출원리 공시자료', 'ai_draft', 'high', 'admin'),
  ('term', '자연보험료(自然保險料) 방식', '매 보험기간 실제 위험률에 맞춰 보험료를 산출하는 방식으로, 연령이 높아질수록 사망·질병 위험이 커져 보험료가 매년 상승하는 구조다. 갱신형보험과 1년 단위 단체보험 등이 자연보험료 방식을 따르며, 초기 보험료는 저렴하지만 갱신 시마다 오른다. 평준보험료와 대비되는 개념으로, 갱신형 특약 보험료 인상의 원리를 설명할 때 쓰인다.', '상품구조특약', array['자연보험료','평준보험료','갱신보험료','위험률','보험료인상'], 'cycle3_mined', 'cycle3_mined', '보험업감독규정 및 생명보험협회 보험료 산출원리 공시자료', 'ai_draft', 'high', 'admin'),
  ('term', '가입금액 비례 보장과 정액 보장의 차이', '정액보장은 보험사고 발생 시 가입금액에 따라 약정된 금액을 그대로 지급하는 방식이고, 비례보장은 실제 손해액 범위 내에서 가입금액 비율만큼 보상하는 방식이다. 생명보험·진단비 특약은 정액보장이 원칙이고, 손해보험 실손·재물보험은 비례보장을 따른다. 같은 위험이라도 보장 방식에 따라 지급액 산출 구조가 완전히 다르다.', '상품구조특약', array['정액보장','비례보장','가입금액','손해보상','지급방식'], 'cycle3_mined', 'cycle3_mined', '생명·손해보험협회 표준약관 및 상법 보험편', 'ai_draft', 'high', 'admin'),
  ('term', '정기특약과 종신특약(주계약 부가 사망특약)', '주계약에 부가하는 사망보장 특약은 보장기간이 일정 기간으로 한정된 정기특약과 평생 보장되는 종신특약으로 나뉜다. 정기특약은 보험료가 저렴해 특정 기간 보장 강화에 쓰이고, 종신특약은 평생 보장을 추가할 때 사용된다. 같은 사망보장이라도 주계약 형태와 특약 형태, 정기·종신 여부에 따라 보험료와 보장 종료 시점이 다르다.', '상품구조특약', array['정기특약','종신특약','사망특약','보장기간','주계약부가'], 'cycle3_mined', 'cycle3_mined', '생명보험협회 표준약관 및 보험상품 공시기준', 'ai_draft', 'medium', 'admin'),
  ('term', '갱신형 특약의 자동갱신과 갱신거절', '갱신형 특약은 보험기간 만료 시 계약자가 별도 의사표시를 하지 않으면 동일 조건으로 자동 갱신되는 것이 원칙이며, 갱신 시점 연령·위험률에 따라 보험료가 재산출된다. 다만 보험회사는 정당한 사유 없이 갱신을 거절할 수 없으며, 계약자는 갱신을 원하지 않으면 만기 전 거절 의사를 표시할 수 있다. 자동갱신 구조와 갱신보험료 변동은 가입 시 명확히 설명해야 할 핵심 사항이다.', '상품구조특약', array['자동갱신','갱신거절','갱신형특약','갱신보험료','갱신주기'], 'cycle3_mined', 'cycle3_mined', '생명·손해보험협회 표준약관 갱신 관련 조항', 'ai_draft', 'medium', 'admin'),
  ('term', '전기납·단기납·일시납(보험료 납입방식 구분)', '전기납은 보험기간 전체에 걸쳐 보험료를 내는 방식, 단기납은 보험기간보다 짧게(예: 10·20년) 납입을 완료하는 방식, 일시납은 가입 시 보험료 전액을 한 번에 내는 방식이다. 같은 보장이라도 납입기간이 짧을수록 회차당 보험료는 높지만 총 납입액과 사업비 부담은 달라진다. 납입방식 선택은 해지환급금·세제혜택·납입면제 효과에 영향을 준다.', '상품구조특약', array['전기납','단기납','일시납','납입방식','납입기간'], 'cycle3_mined', 'cycle3_mined', '생명보험협회 보험상품 공시 가이드라인 및 표준약관', 'ai_draft', 'high', 'admin'),
  ('term', '선납(보험료 선납제도)', '앞으로 낼 보험료를 미리 한꺼번에 납입하는 제도로, 통상 일정 기간분을 선납할 수 있으며 선납 시 예정이율로 할인된 금액을 적용받는다. 선납 기간 중에는 매월 자동이체가 발생하지 않아 실효 위험이 줄지만, 비과세 저축성보험에서는 선납이 월적립식 비과세 요건에 영향을 줄 수 있어 주의가 필요하다. 선납 보험료에 대한 할인 적용 여부와 한도는 약관에 정해져 있다.', '상품구조특약', array['선납','보험료선납','예정이율할인','자동이체','비과세요건'], 'cycle3_mined', 'cycle3_mined', '생명보험협회 표준약관 및 보험업감독규정', 'ai_draft', 'medium', 'admin'),
  ('term', '적립부분과 보장부분(보험료 적립 구조)', '보험료는 위험을 보장하는 보장부분과 만기·중도에 환급하기 위해 쌓이는 적립부분으로 나뉘며, 적립부분은 공시이율이나 예정이율로 부리되어 적립금을 형성한다. 보장성보험은 적립부분이 작거나 없고, 저축성·연금보험은 적립부분이 크다. 적립금은 해지환급금·만기환급금·중도인출·약관대출의 기초가 된다.', '상품구조특약', array['적립부분','보장부분','적립금','공시이율부리','환급재원'], 'cycle3_mined', 'cycle3_mined', '생명보험협회 보험상품 공시 가이드라인 및 표준약관', 'ai_draft', 'medium', 'admin'),
  ('term', '보험가입 후 적립금 부리 방식(금리확정형·금리연동형)', '적립금에 적용되는 이율 방식은 가입 시 정한 예정이율을 만기까지 고정하는 금리확정형과 시중금리에 따라 공시이율이 매월 변동하는 금리연동형으로 나뉜다. 금리확정형은 금리 하락기에 유리하고, 금리연동형은 금리 상승기에 유리하나 최저보증이율로 하한이 보장된다. 동일 상품이라도 부리 방식에 따라 장래 적립금과 환급금이 크게 달라진다.', '상품구조특약', array['금리확정형','금리연동형','공시이율','최저보증이율','적립금부리'], 'cycle3_mined', 'cycle3_mined', '보험업감독규정 및 생명보험협회 공시이율 산출기준', 'ai_draft', 'medium', 'admin'),
  ('term', '순수보장형과 만기환급형(보장성보험 환급 구조)', '순수보장형은 만기 시 환급금이 없는 대신 보험료가 저렴하고 보장에 집중한 구조이며, 만기환급형은 만기 시 납입보험료 일부 또는 전부를 돌려받는 대신 보험료가 더 비싸다. 같은 보장이라도 환급형은 적립보험료가 추가되어 보험료가 높아진다. 보장 목적 대비 비용 효율을 비교할 때 핵심이 되는 구분이다.', '상품구조특약', array['순수보장형','만기환급형','환급구조','적립보험료','보장성보험'], 'cycle3_mined', 'cycle3_mined', '생명보험협회 보험상품 공시 가이드라인 및 표준약관', 'ai_draft', 'high', 'admin'),
  ('term', '적립순보험료와 사업비(보험가격지수)', '보험가격지수는 동일 유형 상품의 평균 보험료 대비 해당 상품의 보험료 수준을 100을 기준으로 나타낸 지표로, 100보다 낮으면 평균보다 저렴함을 의미한다. 사업비(부가보험료)는 보험료에 포함되어 모집·관리비용으로 쓰이며 해지환급금이 적은 이유의 하나다. 보험가격지수와 사업비 공시는 상품 비교 시 가격 경쟁력을 판단하는 객관 지표다.', '상품구조특약', array['보험가격지수','사업비','부가보험료','상품비교','해지환급금'], 'cycle3_mined', 'cycle3_mined', '생명·손해보험협회 보험상품 비교공시(보험가격지수) 기준', 'ai_draft', 'medium', 'admin'),
  ('term', '해지환급금 산출 구조(적립금-미상각신계약비)', '해지환급금은 적립금에서 아직 회수되지 않은 신계약비(미상각신계약비)를 차감해 산출되므로, 가입 초기에는 사업비가 많이 빠져 환급금이 납입보험료보다 크게 적다. 시간이 지나 신계약비가 상각될수록 환급금이 적립금에 근접한다. 무·저해지형은 이 차감 구조에 더해 환급금을 의도적으로 낮춰 보험료를 인하한 것이다.', '상품구조특약', array['해지환급금','미상각신계약비','적립금','사업비상각','환급금산출'], 'cycle3_mined', 'cycle3_mined', '보험업감독규정 및 생명보험협회 해지환급금 산출기준', 'ai_draft', 'medium', 'admin'),
  ('term', '보험료 납입주기(월납·분기납·반기납·연납)', '보험료는 매월 내는 월납을 비롯해 3개월마다 내는 분기납, 6개월마다 내는 반기납, 1년에 한 번 내는 연납으로 납입주기를 선택할 수 있다. 납입주기가 길수록 회차당 금액은 크지만 예정이율 할인이 적용되어 총 납입액이 줄어드는 경우가 있다. 납입주기는 자동이체·실효 위험·할인과 연결되므로 계약자 자금 사정에 맞춰 선택한다.', '상품구조특약', array['납입주기','월납','연납','납입할인','자동이체'], 'cycle3_mined', 'cycle3_mined', '생명보험협회 표준약관 및 보험료 납입 관련 공시기준', 'ai_draft', 'medium', 'admin'),
  ('term', '보장의 면책기간·감액기간·대기기간 구분', '면책기간은 보장 자체가 적용되지 않는 기간, 감액기간은 보장은 되나 보험금이 일정 비율 감액 지급되는 기간, 대기기간(부책 전 기간)은 일정 질병 보장이 개시되기 전 기다려야 하는 기간을 말한다. 암진단비는 통상 계약일부터 90일 면책 후 가입 1~2년 내 50% 감액 지급되는 구조가 대표적이다. 세 개념을 혼동하면 보험금 지급 시점·금액 안내에 오류가 생긴다.', '상품구조특약', array['면책기간','감액기간','대기기간','암진단비','보장개시'], 'cycle3_mined', 'cycle3_mined', '생명보험협회 표준약관 및 질병보험 표준화 기준', 'ai_draft', 'high', 'admin'),
  ('term', '특약 보험가입한도와 비례감액', '특정 진단비·입원비 특약은 1인당 또는 회사 간 합산 가입한도가 정해져 있으며, 한도를 초과해 가입하면 인수가 제한되거나 보험사고 시 비례감액 지급될 수 있다. 도덕적 위험과 과다보험을 막기 위한 장치로, 중복·과다 가입 방지 가이드라인과 연결된다. 다수 계약 보유 고객 설계 시 합산 한도 확인이 필수다.', '상품구조특약', array['가입한도','비례감액','과다보험','합산한도','도덕적위험'], 'cycle3_mined', 'cycle3_mined', '생명·손해보험협회 중복·과다 보험가입 방지 가이드라인', 'ai_draft', 'medium', 'admin'),
  ('term', '실손의료보험 특약과 주계약의 분리 구조', '실손의료보험은 단독형으로 가입하거나 다른 주계약에 특약 형태로 부가할 수 있으며, 2013년 1월부터 보험사의 단독형 실손 병행판매가 의무화되어 종합보험에 끼워파는 관행이 제한됐고 이후 끼워팔기가 금지됐다. 특약형으로 가입한 실손은 주계약 해지·만기 시 함께 종료될 수 있어 단독 유지 가능 여부를 확인해야 한다. 실손은 갱신·재가입 주기와 세대 구분이 별도로 적용된다.', '상품구조특약', array['실손특약','단독형실손','주계약분리','실손갱신','끼워팔기금지'], 'cycle3_mined', 'cycle3_mined', '금융위원회 단독형 실손의료보험 도입 방안 및 보험업감독규정(2013 시행)', 'ai_draft', 'high', 'admin'),
  ('term', '보험기간과 납입기간의 분리', '보험기간은 보장이 유효한 기간이고 납입기간은 보험료를 내는 기간으로, 두 기간은 같을 수도(전기납) 다를 수도(단기납) 있다. 예컨대 80세 만기·20년납이면 보험료는 20년만 내고 보장은 80세까지 이어진다. 납입기간 종료 후에도 보장이 계속되므로 납입완료와 보장종료를 혼동하지 않도록 설명해야 한다.', '상품구조특약', array['보험기간','납입기간','전기납','단기납','만기'], 'cycle3_mined', 'cycle3_mined', '생명·손해보험협회 표준약관', 'ai_draft', 'high', 'admin'),
  ('term', '태아보험(어린이보험 태아가입특약)', '태아보험은 출생 전 태아 상태에서 어린이보험에 가입하면서 임신·출산 관련 위험과 선천이상·저체중 등을 보장하는 태아특약을 부가하는 구조다. 태아는 보험계약상 피보험자가 될 수 없어 출생 시 피보험자로 전환(태아등재)되며, 핵심 태아특약은 가입 가능 임신주수(통상 22주 전후, 회사별 상이)에 제한이 있다. 출생 후에는 어린이보험 본계약으로 보장이 이어진다.', '상품구조특약', array['태아보험','태아특약','어린이보험','임신주수','선천이상'], 'cycle3_mined', 'cycle3_mined', '법제처 찾기쉬운 생활법령정보(태아보험 가입) 및 생명·손해보험협회 어린이보험 인수기준', 'ai_draft', 'medium', 'admin'),
  ('term', '연생보험(2인 이상 피보험자 구조)', '연생보험은 한 계약에 둘 이상의 피보험자를 두어 그중 특정인의 사망·생존 시 보험금을 지급하는 구조로, 부부형·연금 연생형 등이 있다. 부부 중 먼저 사망한 사람 기준 지급, 마지막 생존자 기준 지급 등 약정 방식이 다양하다. 타인의 사망을 보험사고로 하는 경우 상법 제731조에 따라 각 피보험자의 서면동의가 모두 필요하며, 동의가 없으면 계약이 무효가 된다.', '상품구조특약', array['연생보험','복수피보험자','부부형','피보험자동의','연금연생'], 'cycle3_mined', 'cycle3_mined', '생명보험협회 표준약관 및 상법 제731조(타인의 생명보험)', 'ai_draft', 'medium', 'admin'),
  ('term', '단체보험과 개인보험 구조 차이', '단체보험은 회사·단체가 계약자가 되어 소속 구성원을 피보험자로 일괄 가입하는 구조로, 통상 1년 단위 갱신·자연보험료 방식이며 개별 고지 부담이 적다. 개인보험은 개인이 직접 계약자·피보험자가 되어 장기 평준보험료로 가입한다. 단체보험은 퇴직 시 개인보험 전환(개인 계속가입) 제도가 적용될 수 있다.', '상품구조특약', array['단체보험','개인보험','단체갱신','개인전환','계약자'], 'cycle3_mined', 'cycle3_mined', '생명·손해보험협회 단체보험 표준약관', 'ai_draft', 'medium', 'admin'),
  ('term', '갱신형과 비갱신형 특약 혼합설계', '하나의 상품에서 일부 특약은 갱신형, 일부는 비갱신형으로 혼합 설계할 수 있어, 초기 보험료 부담과 장기 인상 위험을 조정하는 데 쓰인다. 비갱신형은 가입 시 보험료가 만기까지 고정되어 총액 예측이 쉽고, 갱신형은 초기 저렴하나 갱신 시 인상된다. 같은 보장을 어느 구조로 담는지에 따라 장기 총납입액이 크게 달라진다.', '상품구조특약', array['갱신형','비갱신형','혼합설계','보험료고정','장기총액'], 'cycle3_mined', 'cycle3_mined', '생명·손해보험협회 표준약관 및 보험상품 공시기준', 'ai_draft', 'medium', 'admin'),
  ('term', '진단비 특약의 1회 지급과 다회 지급(재진단·재발 보장)', '진단비 특약은 최초 진단 시 1회만 지급되는 형태가 기본이나, 암 등 일부 특약은 재발·전이·2차암 진단 시 추가 지급하는 다회 지급(재진단) 구조로 설계되기도 한다. 다회 지급형은 보장 공백기간과 지급 횟수 제한이 함께 설정되는 것이 일반적이다. 1회형과 다회형은 보험료와 실질 보장 범위가 다르다.', '상품구조특약', array['진단비','다회지급','재진단','재발보장','지급횟수'], 'cycle3_mined', 'cycle3_mined', '생명보험협회 질병보험 표준약관 및 표준화 기준', 'ai_draft', 'medium', 'admin'),
  ('term', '중도인출 가능 한도와 적립금 차감', '유니버셜·저축성보험은 적립금 범위 내에서 일정 한도(통상 연 일정 횟수·해지환급금의 일부)까지 적립금을 빼서 쓰는 중도인출이 가능하며, 인출액만큼 적립금과 향후 환급금·보험금이 줄어든다. 약관대출과 달리 이자가 없으나 인출분이 영구 차감되는 점이 다르다. 중도인출은 비과세 요건·보장금액에 영향을 줄 수 있어 주의가 필요하다.', '상품구조특약', array['중도인출','적립금차감','유니버셜','약관대출구분','비과세영향'], 'cycle3_mined', 'cycle3_mined', '생명보험협회 유니버셜·저축성보험 표준약관', 'ai_draft', 'medium', 'admin'),
  ('term', '보험료 할인 유형(다자녀·건강체·고액·이체할인)', '보험료 할인은 위험 감소를 반영한 비흡연·우량체 할인 외에도 가입금액이 큰 경우의 고액계약 할인, 자녀 수에 따른 다자녀 할인, 자동이체·신용카드 납입 할인 등 다양하게 운영된다. 할인 종류와 율은 상품·회사별로 다르며 중복 적용 가능 여부도 약관에 정해진다. 할인 적용은 동일 보장 대비 실질 보험료를 낮추는 설계 요소다.', '상품구조특약', array['보험료할인','다자녀할인','고액계약할인','이체할인','우량체할인'], 'cycle3_mined', 'cycle3_mined', '생명·손해보험협회 보험상품 공시기준 및 약관', 'ai_draft', 'medium', 'admin'),
  ('term', '보험료 산출 3대 예정기초율(예정위험률·예정이율·예정사업비율)', '보험료는 예정위험률(사망·질병 발생 확률), 예정이율(적립금 운용 예상 수익률), 예정사업비율(모집·관리비용 비율)이라는 세 예정기초율로 산출된다(3이원 방식). 예정이율이 높으면 보험료가 낮아지고, 예정위험률·예정사업비율이 높으면 보험료가 올라간다. 이 기초율과 실제 경험률의 차이가 배당(차익)의 원천이 된다.', '상품구조특약', array['예정위험률','예정이율','예정사업비율','보험료산출','예정기초율'], 'cycle3_mined', 'cycle3_mined', '보험업감독규정 및 생명보험협회 보험료 산출원리 공시자료', 'ai_draft', 'high', 'admin'),
  ('term', '3이원 배당(이차익·사차익·비차익)', '배당보험의 배당은 예정기초율과 실제 경험의 차이에서 발생하며, 자산운용 수익이 예정이율을 초과한 이차익, 실제 사망·질병이 예정보다 적은 사차익, 사업비를 예정보다 적게 쓴 비차익으로 구성된다. 세 이원에서 생긴 잉여를 계약자에게 환원하는 것이 계약자배당이다. 무배당보험은 이 배당을 하지 않는 대신 보험료가 낮다.', '상품구조특약', array['3이원배당','이차익','사차익','비차익','계약자배당'], 'cycle3_mined', 'cycle3_mined', '보험업감독규정 및 생명보험협회 계약자배당 산출기준', 'ai_draft', 'high', 'admin'),
  ('term', '보험계약대출 이율과 연체이자', '보험계약대출(약관대출)은 해약환급금 범위 내에서 받는 대출로, 적용 이율은 보험상품의 예정이율 또는 공시이율에 가산금리를 더해 산출된다. 대출이자를 연체하면 미상환 원리금이 해약환급금을 초과하는 시점에 계약이 해지될 수 있다. 금리연동형은 공시이율 변동에 따라 대출이율도 변동한다.', '법령감독규정', array['보험계약대출','약관대출이율','가산금리','해약환급금','대출이자연체'], 'cycle3_mined', 'cycle3_mined', '보험업감독규정 및 생명보험 표준약관 보험계약대출 조항', 'ai_draft', 'medium', 'admin'),
  ('term', '보험나이(상령일) 계산법', '보험나이는 계약일 현재 피보험자의 실제 만 나이를 기준으로 6개월 미만의 끝수는 버리고 6개월 이상의 끝수는 1년으로 올려 계산하며, 이후 매년 계약 해당일에 1세씩 증가한다. 보험나이가 한 살 올라가는 날을 상령일이라 하며, 상령일이 지나면 보험료가 인상되므로 가입 시점 판단에 중요하다.', '법령감독규정', array['보험나이','상령일','만나이','보험료산출','가입연령'], 'cycle3_mined', 'cycle3_mined', '보험업감독업무 시행세칙 별표15 표준약관 제21조(보험나이 등)', 'ai_draft', 'high', 'admin'),
  ('term', '손해사정 동의제도', '보험회사가 손해사정사에게 손해사정을 위탁할 때, 보험계약자나 피보험자에게 손해사정 결과를 설명하고 일정 절차를 거치도록 한 제도다. 소비자가 손해사정 결과에 이의를 제기하거나 독립 손해사정사를 선임할 권리를 보호하기 위한 장치다.', '법령감독규정', array['손해사정동의','손해사정위탁','독립손해사정','소비자권리','보험금사정'], 'cycle3_mined', 'cycle3_mined', '보험업법 및 보험업감독규정 손해사정 관련 조항', 'ai_draft', 'medium', 'admin'),
  ('term', '단체보험 보험수익자 지정 규제', '단체가 구성원을 피보험자로 하는 단체보험에서 피보험자 또는 그 상속인이 아닌 자(회사 등)를 보험수익자로 지정하려면, 단체의 규약에서 명시적으로 정하는 경우를 제외하고는 피보험자의 서면 동의를 받아야 한다. 이 요건을 갖추지 않은 수익자 지정은 효력이 없고, 그 경우 피보험자 또는 상속인이 보험수익자가 된다.', '법령감독규정', array['단체보험','수익자지정','피보험자동의','사망보험금','상법단체보험'], 'cycle3_mined', 'cycle3_mined', '상법 제735조의3(단체보험) 및 대법원 2017다215728 판결', 'ai_draft', 'high', 'admin'),
  ('term', '보험가입증명서(가입증명원)', '보험가입 사실을 입증하기 위해 보험회사가 발급하는 서류로, 계약자·피보험자·보험종목·보장내용·보험기간 등이 기재된다. 단체 입찰, 대출, 비자 발급 등에서 보험 가입 사실 증명용으로 활용되며 보험증권과는 발급 목적이 다르다.', '법령감독규정', array['보험가입증명서','가입증명원','보험가입사실','증명서류','보험증권차이'], 'cycle3_mined', 'cycle3_mined', '보험회사 표준 서식 및 보험업감독규정', 'ai_draft', 'medium', 'admin'),
  ('term', '실손보험 자동갱신과 갱신거절 제한', '실손의료보험은 보장기간 만료 후 자동갱신되는 구조이며, 보험회사는 피보험자의 건강상태 악화나 보험금 수령 이력을 이유로 갱신을 거절할 수 없다. 다만 재가입 주기 도래 시에는 변경된 상품으로 재가입하게 된다.', '법령감독규정', array['실손자동갱신','갱신거절금지','재가입주기','보장연속성','실손의료보험'], 'cycle3_mined', 'cycle3_mined', '실손의료보험 표준약관 및 보험업감독규정', 'ai_draft', 'high', 'admin'),
  ('term', '보험료 납입 일시중지 기능(유니버셜)', '유니버셜 기능이 있는 보험은 의무납입기간 경과 후 일정 기간 보험료 납입을 일시 중지하더라도 적립금에서 위험보험료와 사업비를 충당하여 계약을 유지할 수 있다. 다만 적립금이 부족해지면 계약이 해지될 수 있어 납입 재개가 필요하다.', '법령감독규정', array['납입일시중지','유니버셜기능','의무납입기간','적립금','계약유지'], 'cycle3_mined', 'cycle3_mined', '변액유니버셜·유니버셜보험 표준약관', 'ai_draft', 'medium', 'admin'),
  ('term', '중대질병(CI) 보험금 일부 선지급 구조', 'CI보험은 중대한 암·뇌졸중·급성심근경색 등 약관에서 정한 중대질병이 발생하면 사망보험금의 일부(예 50~80%)를 미리 지급하는 구조다. 선지급된 금액은 이후 사망보험금에서 차감되며, ''중대한''의 정의가 일반 진단비 특약보다 엄격하다.', '법령감독규정', array['CI보험','선지급','중대질병정의','사망보험금차감','중대한암'], 'cycle3_mined', 'cycle3_mined', 'CI보험 표준약관 및 중대질병 정의 조항', 'ai_draft', 'medium', 'admin'),
  ('term', '보험모집 적합성 진단(보험판매 적합성)', '보험회사·모집인은 일반금융소비자에게 보장성보험 등을 권유하기 전에 연령·재산상황·가입목적 등을 파악하여 적합한 상품을 권유해야 하며, 그 결과를 적합성진단서 등으로 확인받는다. 부적합한 상품 권유는 금융소비자보호법상 적합성 원칙 위반이다.', '법령감독규정', array['적합성진단','보험판매적합성','권유전확인','적합성진단서','금소법'], 'cycle3_mined', 'cycle3_mined', '금융소비자보호법 제17조(적합성원칙) 및 감독규정', 'ai_draft', 'high', 'admin'),
  ('term', '보험금 압류금지(생계형 보험금)', '민사집행법은 일정 범위의 보장성 보험금과 해약환급금을 압류금지 재산으로 정하고 있다. 시행령상 사망보험금 등 보장성 보험금 일부와 해약환급금의 일정 금액은 채권자가 압류할 수 없어, 채무가 있어도 최소한의 보장이 유지된다. 한도는 시행령 개정으로 변동되므로 청구 시점 기준을 확인해야 한다.', '법령감독규정', array['보험금압류금지','압류금지재산','해약환급금압류','생계형보험','민사집행법'], 'cycle3_mined', 'cycle3_mined', '민사집행법 제246조 및 시행령 제6조(압류금지 보장성 보험금 등의 범위)', 'ai_draft', 'high', 'admin'),
  ('term', '보험계약 명의변경(계약자 변경) 절차', '계약자 변경은 기존 계약자와 새 계약자, 피보험자(타인 계약 시 동의)의 합의로 이루어지며 보험회사의 승낙과 명의변경 신청서가 필요하다. 변경에 따라 증여세 등 세무 문제가 발생할 수 있고, 변경 시점 이후의 권리·의무가 새 계약자에게 이전된다.', '법령감독규정', array['계약자변경','명의변경','증여세','피보험자동의','권리의무이전'], 'cycle3_mined', 'cycle3_mined', '보험 표준약관(계약자 변경) 및 상속세및증여세법', 'ai_draft', 'medium', 'admin'),
  ('term', '보험증권 재발급', '보험증권을 분실·훼손한 경우 계약자는 보험회사에 재발급을 신청할 수 있으며, 재발급된 증권은 원본과 동일한 효력을 가진다. 증권 분실 자체가 계약 효력에 영향을 주지는 않으며 보험금 청구도 가능하다.', '법령감독규정', array['보험증권재발급','증권분실','재발급신청','증권효력','계약유지'], 'cycle3_mined', 'cycle3_mined', '보험 표준약관(보험증권 재발급 조항)', 'ai_draft', 'high', 'admin'),
  ('term', '피보험자 동의 철회권(생명보험)', '타인의 생명보험에서 서면동의를 한 피보험자는 계약 효력 발생 후에도 본인의 의사에 따라 서면으로 동의를 철회할 수 있으며, 철회 시 그 계약은 효력을 잃는다. 2010년 개정 생명보험 표준약관에 계약 체결 이후 언제든지 철회할 수 있는 조항이 신설되었다. 이는 피보험자의 자기결정권과 도덕적 위험 방지를 위한 보호장치다.', '법령감독규정', array['피보험자동의철회','서면동의철회','타인생명보험','계약실효','도덕적위험'], 'cycle3_mined', 'cycle3_mined', '상법 제731조 및 생명보험 표준약관(2010년 개정 동의 철회 조항)', 'ai_draft', 'high', 'admin'),
  ('term', '보험회사 지급여력비율(K-ICS)', '지급여력비율은 보험회사가 보험금 지급 의무를 이행할 수 있는 재무건전성 지표로, 가용자본을 요구자본으로 나눈 값이다. 2023년부터 신지급여력제도(K-ICS)가 적용되며 감독당국은 일정 비율 이상 유지를 권고한다. 보험사 선택 시 건전성 판단 지표로 활용된다.', '법령감독규정', array['지급여력비율','K-ICS','재무건전성','가용자본','보험사선택'], 'cycle3_mined', 'cycle3_mined', '보험업감독규정(지급여력제도) 및 금융감독원 공시', 'ai_draft', 'medium', 'admin'),
  ('term', '보험상품 비교공시(생명·손해보험협회)', '생명보험협회와 손해보험협회는 회원사 보험상품의 보험료·보장내용·해약환급금 등을 비교할 수 있도록 공시 사이트를 운영한다. 소비자가 동일 유형 상품을 객관적으로 비교할 수 있게 하는 제도로, 모집 시 객관적 비교 근거로 활용된다.', '법령감독규정', array['보험상품비교공시','협회공시','상품비교','보험료비교','공시사이트'], 'cycle3_mined', 'cycle3_mined', '생명보험협회·손해보험협회 상품비교공시 운영기준', 'ai_draft', 'medium', 'admin'),
  ('term', '보험금 지급 관련 의료자문 제도', '보험회사가 보험금 지급 심사 과정에서 자사 자문의나 제3 의료기관에 의학적 소견을 구하는 절차다. 의료자문 결과만으로 부지급을 결정할 수 없고, 객관성 확보를 위해 동의 절차와 자문 내역 안내 등이 요구된다. 분쟁이 잦은 영역이다.', '법령감독규정', array['의료자문','자문의','제3의료기관','보험금심사','부지급분쟁'], 'cycle3_mined', 'cycle3_mined', '보험업감독규정 및 의료자문 관련 약관·지침', 'ai_draft', 'medium', 'admin'),
  ('term', '보험료 추가납입(기본보험료 대비 한도)', '적립형·저축성 보험에서 기본보험료 외에 추가로 보험료를 납입하는 기능으로, 통상 기본보험료의 일정 배수(예 2배)까지 가능하다. 추가납입 보험료는 사업비가 낮게 부과되어 적립효율이 높은 편이며 비과세 한도 산정에 포함될 수 있다.', '법령감독규정', array['추가납입','기본보험료','추가납입한도','사업비','적립효율'], 'cycle3_mined', 'cycle3_mined', '저축성·연금보험 표준약관(추가납입 조항)', 'ai_draft', 'medium', 'admin'),
  ('term', '보험사고 조사 및 자료 제출 협조의무', '보험금 청구 시 보험회사는 사고 사실과 손해 정도를 확인하기 위해 조사를 할 수 있고, 청구자는 손해 입증과 사고 조사에 필요한 자료 제출에 협조해야 한다. 정당한 이유 없이 협조하지 않으면 그로 인해 늘어난 손해에 대해 보험금이 제한될 수 있다.', '법령감독규정', array['사고조사','자료제출협조','손해입증','보험금심사','협조의무'], 'cycle3_mined', 'cycle3_mined', '보험 표준약관(보험금 청구 및 조사 협조) 조항', 'ai_draft', 'medium', 'admin'),
  ('term', '보험료 영수(수금)와 가지급금 처리', '보험회사 또는 모집종사자가 보험료를 받으면 영수증을 교부해야 하며, 모집인이 회사에 입금하기 전 받은 보험료는 회사가 책임진다. 모집인이 보험료를 횡령·미입금한 경우라도 계약자가 정당하게 납입했다면 회사가 보호한다.', '법령감독규정', array['보험료영수','수금','영수증교부','모집인횡령','회사책임'], 'cycle3_mined', 'cycle3_mined', '보험업법 및 보험 표준약관(보험료 영수 및 효력)', 'ai_draft', 'medium', 'admin'),
  ('term', '보험가입내역 조회(생명·손해보험협회)', '본인의 전 보험회사 가입내역을 생명보험협회·손해보험협회의 조회 시스템(내보험찾아줌 등)을 통해 통합 확인할 수 있는 제도다. 숨은보험금·휴면보험금 조회와 함께 중복가입 점검, 상속인의 피상속인 계약 조회에 활용된다.', '법령감독규정', array['보험가입내역조회','내보험찾아줌','숨은보험금','중복가입점검','상속인조회'], 'cycle3_mined', 'cycle3_mined', '생명보험협회·손해보험협회 보험가입조회 시스템 운영기준', 'ai_draft', 'medium', 'admin'),
  ('term', '보험료 신용카드 납입 거절 문제', '보장성보험의 신용카드 납입 허용 여부는 보험회사·상품별로 다르며, 카드 가맹점 수수료 등을 이유로 카드납을 제한하는 경우가 있다. 금융당국은 카드납 확대를 권고하고 있으나 법적 의무는 아니어서 상품마다 가능 여부가 다르다.', '법령감독규정', array['카드납입','신용카드보험료','카드납제한','납입방법','수수료'], 'cycle3_mined', 'cycle3_mined', '보험업감독규정 및 금융위원회 카드납 관련 행정지도', 'ai_draft', 'medium', 'admin'),
  ('term', '보험금 지급 후 구상(보험자대위)과 가족면책', '보험회사가 보험금을 지급한 뒤 손해를 일으킨 제3자에게 구상권을 행사할 때, 그 제3자가 피보험자와 생계를 같이하는 가족인 경우에는 그 가족의 고의로 인한 손해가 아닌 한 구상권 행사가 제한된다. 가족 간 사고에서 구상으로 인한 가계 부담을 막기 위한 규정이다.', '법령감독규정', array['보험자대위가족면책','구상권제한','생계동일가족','제3자대위','고의제외'], 'cycle3_mined', 'cycle3_mined', '상법 제682조 제2항(보험자대위) 및 관련 판례', 'ai_draft', 'high', 'admin'),
  ('term', '표준이율과 책임준비금 적립', '표준이율은 보험회사가 책임준비금을 적립할 때 적용하는 기준이율로 감독당국이 고시하며, 보험회사의 보험금 지급 재원 확보 건전성과 연결된다. 표준이율 변동은 신상품 예정이율·보험료 수준에 영향을 줄 수 있다.', '법령감독규정', array['표준이율','책임준비금','적립기준','예정이율','건전성'], 'cycle3_mined', 'cycle3_mined', '보험업감독규정(책임준비금 및 표준이율) 조항', 'ai_draft', 'medium', 'admin'),
  ('term', '보험금 청구 위임(대리청구)', '피보험자 본인이 직접 청구하기 어려운 경우 위임장·신분증 등을 갖춰 대리인이 보험금을 청구할 수 있다. 지정대리청구인 제도와 달리 일반 위임은 사전 지정이 아닌 건별 위임이며, 보험회사가 정한 본인확인 절차를 거친다.', '법령감독규정', array['보험금대리청구','청구위임','위임장','본인확인','지정대리청구차이'], 'cycle3_mined', 'cycle3_mined', '보험 표준약관(보험금 청구 절차) 및 위임 관련 규정', 'ai_draft', 'medium', 'admin'),
  ('term', '보험약관 변경(약관 불이익 변경 금지)', '보험회사가 약관을 변경하더라도 기존 계약자에게 불리하게 소급 적용할 수 없는 것이 원칙이며, 약관 변경 시 감독당국 신고·승인 절차를 거쳐야 한다. 변경 내용이 계약자에게 유리한 경우에는 기존 계약에 적용하기도 한다.', '법령감독규정', array['약관변경','불이익변경금지','소급적용금지','약관신고','계약자보호'], 'cycle3_mined', 'cycle3_mined', '약관규제법 및 보험업감독규정(약관 신고·변경)', 'ai_draft', 'medium', 'admin');
